const ALL = [
  ['Linguagem C','1','Qual a sequência correcta de fases na compilação de um programa em C?',['Compilador → Pré-processador → Linker → Loader','Pré-processador → Compilador → Linker → Loader','Pré-processador → Linker → Compilador → Loader','Compilador → Linker → Pré-processador → Loader'],1,'A sequência é: 1) pré-processador (resolve #include, #define), 2) compilador (gera código objecto), 3) linker (junta objectos e bibliotecas), 4) loader (carrega o executável em memória).','Pré-processador → Compilador → Linker → Loader. Decora esta ordem.<br><a href="sistemas_operacoes_estudo__2_.html#1-compilação-em-c" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §1 Compilação em C ↗</a>'],
  ['Linguagem C','2','Qual a flag do gcc que permite incluir símbolos de debug no executável?',['-O2','-Wall','-g','-c'],2,'A flag -g acrescenta informação de debug (símbolos, números de linha) ao executável, essencial para usar gdb.','-g = debug. -Wall = warnings. -c = só compilar (sem linkar). -O = optimização.<br><a href="sistemas_operacoes_estudo__2_.html#1-compilação-em-c" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §1 Compilação em C ↗</a>'],
  ['Linguagem C','3','Qual a flag do gcc que activa todos os warnings comuns?',['-w','-Wall','-Werror','-Wextra'],1,'-Wall activa a maior parte dos warnings importantes. -w (minúsculo) DESLIGA todos. -Werror trata warnings como erros.','Cuidado: -w (suprime) vs -Wall (activa).<br><a href="sistemas_operacoes_estudo__2_.html#1-compilação-em-c" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §1 Compilação em C ↗</a>'],
  ['Linguagem C','4','O que faz a flag `-c` do gcc?',['Compila e linka, gerando executável','Compila apenas, parando antes da linkagem (gera ficheiro .o)','Limpa ficheiros temporários','Activa modo de debug'],1,'A flag -c diz ao gcc para compilar mas não invocar o linker. O resultado é um ficheiro objecto .o que pode depois ser linkado separadamente.','-c = só compilar (gera .o). Útil para compilar módulos independentemente.<br><a href="sistemas_operacoes_estudo__2_.html#1-compilação-em-c" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §1 Compilação em C ↗</a>'],
  ['Linguagem C','5','O que retorna o operador `sizeof()` quando aplicado a uma variável?',['O número de bits que ocupa','O número de bytes que ocupa em memória','O endereço da variável','O valor da variável'],1,'sizeof retorna o tamanho em bytes que o tipo ou variável ocupa. Por exemplo, em arquitecturas comuns, sizeof(int) é 4.','sizeof retorna bytes. NÃO bits.<br><a href="sistemas_operacoes_estudo__2_.html#2-tipos-de-dados" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §2 Tipos de Dados ↗</a>'],
  ['Linguagem C','6','Qual destes tipos NÃO é um tipo inteiro padrão em C?',['short','long','real','unsigned int'],2,'Em C os tipos inteiros são char, short, int, long, long long, com variantes signed/unsigned. "real" não existe — para vírgula flutuante usa-se float, double, long double.','Inteiros: char/short/int/long. Vírgula flutuante: float/double.<br><a href="sistemas_operacoes_estudo__2_.html#2-tipos-de-dados" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §2 Tipos de Dados ↗</a>'],
  ['Linguagem C','7','Qual a diferença entre `float` e `double`?',['Não há diferença, são sinónimos','`double` tem maior precisão (tipicamente 64 bits) do que `float` (tipicamente 32 bits)','`float` tem maior precisão do que `double`','`double` só pode armazenar valores inteiros'],1,'double = "double precision". Tipicamente float é 32 bits (~7 dígitos decimais) e double é 64 bits (~15 dígitos decimais).','double = mais bits, mais precisão. Default em C para literais reais é double.<br><a href="sistemas_operacoes_estudo__2_.html#2-tipos-de-dados" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §2 Tipos de Dados ↗</a>'],
  ['Linguagem C','8','Para que serve o tipo `void` em C?',['Indica um tipo numérico de precisão dupla','Indica ausência de tipo: usado em funções sem retorno ou com apontadores genéricos (`void *`)','Indica um inteiro de 0 bits','É equivalente a `int`'],1,'void = "nada". Funções que não retornam nada têm tipo de retorno void. void* é um apontador genérico que pode apontar para qualquer tipo.','void = vazio. void* = apontador genérico (cast obrigatório para usar).<br><a href="sistemas_operacoes_estudo__2_.html#1-compilação-em-c" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §1 Compilação em C ↗</a>'],
  ['Linguagem C','9','O que produz `5 % 2` em C?',['2.5','2','1','0'],2,'O operador % é o módulo (resto da divisão inteira). 5 dividido por 2 = 2 com resto 1.','% = resto. Só funciona com inteiros, não com floats.<br><a href="sistemas_operacoes_estudo__2_.html#3-operadores" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §3 Operadores ↗</a>'],
  ['Linguagem C','10','Qual é o operador lógico AND em C?',['&','&&','AND','and'],1,'&& é o AND lógico (curto-circuito). & é bitwise AND. Em C não há palavras "AND"/"and" como operadores.','Lógico: && e ||. Bitwise: & e |.<br><a href="sistemas_operacoes_estudo__2_.html#3-operadores" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §3 Operadores ↗</a>'],
  ['Linguagem C','11','O que faz o operador bitwise `<<` (shift left)?',['Compara dois valores','Desloca os bits para a esquerda, o que equivale a multiplicar por uma potência de 2','Atribui um valor','Faz uma divisão inteira'],1,'a << n desloca os bits de a para a esquerda em n posições, equivalendo a a * 2^n. Por exemplo, 1 << 3 = 8.','<< n equivale a × 2^n. >> n equivale a ÷ 2^n.<br><a href="sistemas_operacoes_estudo__2_.html#3-operadores" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §3 Operadores ↗</a>'],
  ['Linguagem C','12','Qual é a diferença entre `==` e `=` em C?',['São equivalentes','`==` é comparação de igualdade; `=` é atribuição','`=` é comparação; `==` é atribuição','`==` só funciona com strings'],1,'= atribui valor. == compara valores. Confundir os dois é erro clássico: `if (x = 5)` atribui 5 a x e a condição é sempre verdadeira.','Memoriza: 1 igual = atribui; 2 iguais = compara.<br><a href="sistemas_operacoes_estudo__2_.html#1-compilação-em-c" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §1 Compilação em C ↗</a>'],
  ['Linguagem C','13','Numa instrução `switch`, o que acontece se omitires `break` no fim de um caso?',['Erro de compilação','Ocorre "fall-through": a execução continua para o caso seguinte','O programa termina','É feito automaticamente um break implícito'],1,'Sem break a execução cai para o próximo case (fall-through). Às vezes é desejado, mas geralmente é fonte de bugs.','switch sem break → fall-through. Default geralmente vai no fim.<br><a href="sistemas_operacoes_estudo__2_.html#4-estruturas-de-decisão-e-ciclos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §4 Estruturas de Decisão e Ciclos ↗</a>'],
  ['Linguagem C','14','Qual a diferença fundamental entre `while` e `do/while`?',['Não há diferença','O corpo do `do/while` executa pelo menos uma vez (condição testada no fim); o `while` pode não executar se a condição for falsa logo no início','O `while` executa pelo menos uma vez','`do/while` é mais rápido'],1,'while testa a condição ANTES de cada iteração (zero ou mais execuções). do/while testa DEPOIS (uma ou mais execuções).','do { ... } while (cond); → corpo executa pelo menos uma vez.<br><a href="sistemas_operacoes_estudo__2_.html#4-estruturas-de-decisão-e-ciclos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §4 Estruturas de Decisão e Ciclos ↗</a>'],
  ['Linguagem C','15','Numa estrutura `for (int i=0; i<10; i++)`, o que representa cada parte?',['inicialização; incremento; condição','inicialização; condição; incremento (executado no fim de cada iteração)','condição; inicialização; incremento','incremento; condição; inicialização'],1,'O for em C tem três partes: 1) inicialização (uma vez no início), 2) condição (testada antes de cada iteração), 3) incremento (executado no fim de cada iteração).','for(init; cond; step) { body }.<br><a href="sistemas_operacoes_estudo__2_.html#4-estruturas-de-decisão-e-ciclos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §4 Estruturas de Decisão e Ciclos ↗</a>'],
  ['Linguagem C','16','O que armazena uma variável do tipo "apontador para int" (`int *p`)?',['O valor de um inteiro','O endereço de memória onde está armazenado um inteiro','O tamanho de um inteiro','O nome de uma variável inteira'],1,'Apontadores armazenam ENDEREÇOS (não valores). int *p significa "p é um apontador para um inteiro" — p contém o endereço de um int.','Tipo* var → var guarda um endereço para Tipo.<br><a href="sistemas_operacoes_estudo__2_.html#5-apontadores-pointers" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §5 Apontadores (Pointers) ↗</a>'],
  ['Linguagem C','17','Em C, qual é o efeito do operador `&` quando aplicado a uma variável?',['Faz AND lógico','Retorna o endereço de memória da variável','Dereferencia a variável','Faz uma cópia da variável'],1,'&var retorna o endereço de var. É o "operador endereço-de" (address-of). Útil para inicializar apontadores: int *p = &x;','& = endereço-de. * = dereferência (pega no valor apontado).<br><a href="sistemas_operacoes_estudo__2_.html#5-apontadores-pointers" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §5 Apontadores (Pointers) ↗</a>'],
  ['Linguagem C','18','Em C, qual é o efeito do operador `*` quando aplicado a um apontador?',['Multiplica o apontador por 2','Retorna o endereço da variável apontada','Dereferencia o apontador (acede ao valor armazenado no endereço apontado)','Liberta o espaço apontado'],2,'*p significa "o valor armazenado no endereço apontado por p". Por exemplo, se p aponta para uma variável com valor 42, *p é 42.','* na declaração: tipo apontador. * num apontador existente: dereferência.<br><a href="sistemas_operacoes_estudo__2_.html#5-apontadores-pointers" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §5 Apontadores (Pointers) ↗</a>'],
  ['Linguagem C','19','O que é um apontador `NULL`?',['Um apontador que não foi inicializado','Um apontador que aponta deliberadamente para "nada" — NULL é uma constante (tipicamente 0) usada para indicar ausência de endereço válido','Um apontador que aponta para o início da memória','Um apontador apenas para inteiros'],1,'NULL é constante simbólica em <stddef.h> (tipicamente (void*)0). Convenção: apontador inválido / não atribuído. Dereferenciar um NULL gera segmentation fault.','NULL ≠ não inicializado. NULL é um valor explícito. Sempre verificar `if (p != NULL)` antes de dereferenciar.<br><a href="sistemas_operacoes_estudo__2_.html#5-apontadores-pointers" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §5 Apontadores (Pointers) ↗</a>'],
  ['Linguagem C','20','Em C, qual é o índice do primeiro elemento de um array?',['1','0','-1','depende do compilador'],1,'Os arrays em C são indexados a partir de 0. arr[0] é o primeiro elemento. arr[N-1] é o último de um array de tamanho N.','Index 0-based: a[0]...a[n-1] para um array de tamanho n.<br><a href="sistemas_operacoes_estudo__2_.html#6-arrays" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §6 Arrays ↗</a>'],
  ['Linguagem C','21','Como é representada uma string em C?',['Como um tipo nativo `string`','Como um array de caracteres terminado por `\\0` (null terminator)','Como uma classe std::string','Como um apontador para int'],1,'Em C uma string é um array de char terminado por \'\\0\'. As funções de <string.h> assumem este terminador para saber onde a string acaba.','String em C = char[] terminado em \\0. "abc" ocupa 4 bytes (a,b,c,\\0).<br><a href="sistemas_operacoes_estudo__2_.html#7-strings" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §7 Strings ↗</a>'],
  ['Linguagem C','22','Qual a função correcta de `<string.h>` para copiar uma string?',['strcat','strcpy','strcmp','strlen'],1,'strcpy(dest, src) copia src para dest. strcat concatena. strcmp compara. strlen retorna o comprimento (sem o \\0).','cpy=copy, cat=concatenate, cmp=compare, len=length.<br><a href="sistemas_operacoes_estudo__2_.html#7-strings" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §7 Strings ↗</a>'],
  ['Linguagem C','23','O que retorna `strlen("hello")` em C?',['6 (incluindo \\0)','5','4','7'],1,'strlen retorna o comprimento da string SEM contar o \\0 final. "hello" tem 5 caracteres + \\0, mas strlen retorna apenas 5.','strlen NÃO conta o \\0. Mas o array reservado para "hello" precisa de 6 bytes.<br><a href="sistemas_operacoes_estudo__2_.html#7-strings" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §7 Strings ↗</a>'],
  ['Linguagem C','24','Em C, por defeito a passagem de argumentos a funções é:',['Por referência','Por valor (uma cópia do argumento é passada à função)','Por nome','Por endereço sempre'],1,'C usa SEMPRE call-by-value. Modificar o parâmetro dentro da função NÃO afecta o original. Para alterar o original, é preciso passar um apontador.','C = pass-by-value. "Pass-by-reference" simula-se com apontadores: f(&x); void f(int *p) { *p = 5; }.<br><a href="sistemas_operacoes_estudo__2_.html#8-funções--call-by-value-vs-call-by-reference" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §8 Funções — Call by Value vs Call by Reference ↗</a>'],
  ['Linguagem C','25','Como podes simular passagem por referência em C?',['Não é possível em C','Passando o endereço da variável (apontador): a função recebe `tipo *p` e modifica via `*p = ...`','Usando `&` na declaração do parâmetro','Marcando a função como `inline`'],1,'C não tem referências (como C++), mas pode-se passar &var (endereço) e a função recebe um apontador. Modificar *p modifica o original.','Padrão: void swap(int *a, int *b) { int t=*a; *a=*b; *b=t; } chamado como swap(&x,&y);<br><a href="sistemas_operacoes_estudo__2_.html#8-funções--call-by-value-vs-call-by-reference" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §8 Funções — Call by Value vs Call by Reference ↗</a>'],
  ['Linguagem C','26','Qual a função de `<stdlib.h>` usada para alocar memória dinamicamente em runtime?',['alloc()','malloc()','new','create()'],1,'malloc(size) aloca size bytes na heap e devolve um apontador (void*) para o início. Devolve NULL se falhar.','malloc/calloc/realloc para alocar; free para libertar. C não tem `new`/`delete` (isso é C++).<br><a href="sistemas_operacoes_estudo__2_.html#9-alocação-dinâmica-de-memória" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §9 Alocação Dinâmica de Memória ↗</a>'],
  ['Linguagem C','27','Qual é a diferença entre `malloc(n)` e `calloc(n, size)`?',['Não há diferença','`malloc` aloca n bytes não inicializados; `calloc` aloca n*size bytes e inicializa-os a zero','`calloc` é mais rápido','`malloc` aloca na stack; `calloc` na heap'],1,'malloc(n) → n bytes "lixo" (valores indefinidos). calloc(n, size) → n*size bytes a zero. Ambos retornam NULL se falharem.','malloc rápido, mas memória "suja". calloc inicializa a 0. Use o que faz mais sentido.<br><a href="sistemas_operacoes_estudo__2_.html#9-alocação-dinâmica-de-memória" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §9 Alocação Dinâmica de Memória ↗</a>'],
  ['Linguagem C','28','O que faz `free(p)` em C?',['Apaga a variável p','Liberta a memória alocada dinamicamente que p aponta, devolvendo-a ao sistema','Põe p a NULL','Imprime o conteúdo de p'],1,'free(p) liberta a memória que foi previamente alocada com malloc/calloc/realloc no endereço p. Após free, p torna-se "dangling pointer" — usar é UB.','Toda a malloc → tem de haver free. NÃO usar free em apontadores não-malloc. NÃO chamar free duas vezes (double free).<br><a href="sistemas_operacoes_estudo__2_.html#9-alocação-dinâmica-de-memória" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §9 Alocação Dinâmica de Memória ↗</a>'],
  ['Linguagem C','29','O que é um "memory leak"?',['Um vírus de memória','Memória alocada com malloc que nunca é libertada com free, ficando inacessível e desperdiçada','Hardware avariado','Memória física danificada'],1,'Memory leak: alocas com malloc, perdes a referência (sobrescreves o apontador) sem fazer free. A memória continua reservada até o programa terminar.','Cada malloc precisa de uma free correspondente — caso contrário, leak.<br><a href="sistemas_operacoes_estudo__2_.html#9-alocação-dinâmica-de-memória" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §9 Alocação Dinâmica de Memória ↗</a>'],
  ['Linguagem C','30','Como acedes a um campo `nome` de uma struct `pessoa` (variável directa, não apontador)?',['pessoa->nome','pessoa.nome','pessoa[nome]','*pessoa.nome'],1,'Para uma variável struct: usa o operador "." (ponto). Para um apontador para struct: usa o operador "->" (seta).','p.nome → variável. p->nome → apontador (equivalente a (*p).nome).<br><a href="sistemas_operacoes_estudo__2_.html#10-estruturas-struct-e-typedefs" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §10 Estruturas (struct) e Typedefs ↗</a>'],
  ['Linguagem C','31','Para que serve a palavra-chave `typedef` em C?',['Define uma constante','Cria um sinónimo (alias) para um tipo já existente, simplificando declarações','Define uma macro','Importa um tipo de outro ficheiro'],1,'typedef cria alias para tipos. Ex: `typedef struct ponto Ponto;` permite usar `Ponto p;` em vez de `struct ponto p;`.','typedef = renomear tipo. Muito comum com structs e apontadores complexos.<br><a href="sistemas_operacoes_estudo__2_.html#10-estruturas-struct-e-typedefs" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §10 Estruturas (struct) e Typedefs ↗</a>'],
  ['Linguagem C','32','Numa função `int main(int argc, char *argv[])`, o que representa `argc`?',['O conteúdo do primeiro argumento','O número total de argumentos da linha de comandos (incluindo o nome do programa)','O nome do programa','O código de retorno'],1,'argc = argument count: número de argumentos passados na linha de comando, INCLUINDO o nome do programa em argv[0]. Por isso `./prog a b c` dá argc=4.','argc inclui argv[0] (nome do programa). Argumentos reais são argv[1]..argv[argc-1].<br><a href="sistemas_operacoes_estudo__2_.html#11-argumentos-da-linha-de-comandos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §11 Argumentos da Linha de Comandos ↗</a>'],
  ['Linguagem C','33','Em `int main(int argc, char *argv[])`, qual o valor de `argv[0]`?',['O primeiro argumento real do programa','O nome do programa (ou caminho usado para o invocar)','NULL','O número de argumentos'],1,'Por convenção argv[0] é o nome do programa. argv[1] é o primeiro argumento real, e assim sucessivamente até argv[argc-1]. argv[argc] é NULL.','argv[0] = programa, argv[1..argc-1] = argumentos. argv[argc] = NULL (sentinela).<br><a href="sistemas_operacoes_estudo__2_.html#11-argumentos-da-linha-de-comandos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §11 Argumentos da Linha de Comandos ↗</a>'],
  ['Linguagem C','34','O que faz a directiva `#include <stdio.h>`?',['Liga a biblioteca stdio.h ao executável','Indica ao pré-processador para incluir (literalmente, "copy & paste") o conteúdo do ficheiro stdio.h no local da directiva','Importa as classes do stdio','É equivalente a `import` em Java'],1,'#include é processado pelo pré-processador (1ª fase) e simplesmente substitui-se pelo conteúdo do ficheiro indicado. <name> procura nos directórios do sistema; "name" procura primeiro no directório actual.','#include é "copy-paste" textual. NÃO carrega bibliotecas — isso é o linker.<br><a href="sistemas_operacoes_estudo__2_.html#12-o-pré-processador-c" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §12 O Pré-processador C ↗</a>'],
  ['Linguagem C','35','O que faz a directiva `#define PI 3.14`?',['Declara uma variável PI','Define uma macro: o pré-processador substitui textualmente todas as ocorrências de `PI` por `3.14` antes da compilação','Aloca memória para PI','Importa PI de uma biblioteca'],1,'#define faz substituição TEXTUAL antes da compilação. Não é uma variável — é literalmente uma substituição de texto. Por isso convenção: macros em MAIÚSCULAS.','#define = substituição textual. Macros podem ter argumentos: #define MAX(a,b) ((a)>(b)?(a):(b)).<br><a href="sistemas_operacoes_estudo__2_.html#12-o-pré-processador-c" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §12 O Pré-processador C ↗</a>'],
  ['Linguagem C','36','Para que serve a "include guard" típica `#ifndef HEADER_H / #define HEADER_H / ... / #endif`?',['Para acelerar a compilação','Para impedir inclusão múltipla do mesmo header (que daria erros de definição duplicada)','Para fazer debug','Para condicionar plataformas'],1,'Sem guard, se o mesmo header for incluído duas vezes (directa ou indirectamente), os símbolos seriam definidos duas vezes → erro de compilação. O guard verifica se já foi incluído.','Padrão: #ifndef X_H / #define X_H / ... / #endif. Alternativa moderna: #pragma once.<br><a href="sistemas_operacoes_estudo__2_.html#12-o-pré-processador-c" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §12 O Pré-processador C ↗</a>'],
  ['Linguagem C','37','Qual a função do "linker" no processo de construção de um programa C?',['Verifica a sintaxe do código','Junta os ficheiros objecto (.o) e bibliotecas, resolvendo referências entre eles para gerar um executável','Carrega o programa em memória','Optimiza o código'],1,'O linker pega nos .o gerados pelo compilador e nas bibliotecas necessárias, resolve as referências (ex: chamada a printf precisa de saber onde está printf) e gera o executável final.','Pré-processador → Compilador (.o) → Linker (executável) → Loader (memória).<br><a href="sistemas_operacoes_estudo__2_.html#14-compilação-e-linkagem" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §14 Compilação e Linkagem ↗</a>'],
  ['Linguagem C','38','Qual a diferença entre linkagem ESTÁTICA e DINÂMICA?',['Não há diferença','Estática: o código da biblioteca é copiado para dentro do executável (binário maior, autocontido). Dinâmica: o executável apenas referencia a biblioteca, que é carregada em runtime','Dinâmica é sempre mais rápida','Estática só funciona em sistemas Unix'],1,'Estática (.a, .lib): tudo num só ficheiro grande, mas cada programa duplica o código. Dinâmica (.so, .dll): biblioteca partilhada por todos os programas, executável menor, mas depende da .so estar presente em runtime.','Estática = self-contained. Dinâmica = partilhada (.so/.dll) carregada em runtime.<br><a href="sistemas_operacoes_estudo__2_.html#15-linkagem-estática-vs-dinâmica" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §15 Linkagem Estática vs Dinâmica ↗</a>'],
  ['Linguagem C','39','Em Unix, em que ficheiros está tipicamente uma biblioteca dinâmica e o seu header?',['.so e .h respectivamente','.dll e .lib respectivamente','.h e .c respectivamente','.bin e .src respectivamente'],0,'Em Unix: header em .h (declarações: protótipos, tipos, macros). Biblioteca dinâmica em .so (Shared Object). Em Windows seria .h + .dll.','Header (.h) declara; biblioteca (.so/.dll) implementa. O linker precisa de ambos (header para compilar, lib para linkar).<br><a href="sistemas_operacoes_estudo__2_.html#13-bibliotecas-em-c" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §13 Bibliotecas em C ↗</a>'],
  ['Linguagem C','40','Para usar a função `sqrt()` (raiz quadrada) da biblioteca matemática em C, qual a flag necessária para o gcc?',['-lmath','-lm','-math','Não é necessária flag, está em libc'],1,'sqrt está em libm (biblioteca matemática), separada da libc padrão. Tem de se incluir <math.h> E linkar com -lm: gcc prog.c -lm -o prog.','-l<nome> linka libxxx. -lm = libm. Outro exemplo: -lpthread = libpthread.<br><a href="sistemas_operacoes_estudo__2_.html#13-bibliotecas-em-c" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §13 Bibliotecas em C ↗</a>'],
  ['Conceitos Básicos','41','In a single-user PC environment, what is the primary OS goal?',['Maximize resource utilization across 100+ users','Provide ease of use and acceptable performance for one user','Minimize cost of hardware','Handle distributed computing'],1,'The correct answer is \'Provide ease of use and acceptable performance for one user\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#17-o-que-é-um-sistema-operativo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §17 O que é um Sistema Operativo? ↗</a>'],
  ['Conceitos Básicos','42','Multi-user server operating systems prioritize:',['Games and entertainment applications','Fairness and efficient resource utilization across many users','Single user responsiveness','Mobile device efficiency'],1,'The correct answer is \'Fairness and efficient resource utilization across many users\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#17-o-que-é-um-sistema-operativo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §17 O que é um Sistema Operativo? ↗</a>'],
  ['Conceitos Básicos','43','Mobile OS design must balance:',['Only raw speed, ignoring battery life','Usability with battery life and constrained resources','Server performance only','Desktop application compatibility'],1,'The correct answer is \'Usability with battery life and constrained resources\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#17-o-que-é-um-sistema-operativo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §17 O que é um Sistema Operativo? ↗</a>'],
  ['Conceitos Básicos','44','Embedded OS systems typically emphasize:',['Complex user interfaces','Game graphics performance','Reliable operation with minimal user intervention for a dedicated task','Web server functionality'],2,'The correct answer is \'Reliable operation with minimal user intervention for a dedicated task\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#17-o-que-é-um-sistema-operativo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §17 O que é um Sistema Operativo? ↗</a>'],
  ['Conceitos Básicos','45','The OS goals vary by system type. Which is correct?',['All systems prioritize high resource utilization equally','Single-user PCs prioritize ease of use; servers prioritize utilization','Mobile and embedded systems are identical in goals','Goals are independent of hardware'],1,'The correct answer is \'Single-user PCs prioritize ease of use; servers prioritize utilization\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#17-o-que-é-um-sistema-operativo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §17 O que é um Sistema Operativo? ↗</a>'],
  ['Conceitos Básicos','46','In the OS layered hierarchy, what does the OS control?',['Only user applications','Only hardware','Both hardware and provides services to applications','Neither hardware nor applications'],2,'The correct answer is \'Both hardware and provides services to applications\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#19-estrutura-de-um-sistema-computacional" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §19 Estrutura de um Sistema Computacional ↗</a>'],
  ['Conceitos Básicos','47','What is the purpose of resource allocation in the OS?',['To prevent all processes from running','To allocate CPU, memory, I/O devices fairly and efficiently among processes','To remove unused hardware','To disable user programs'],1,'The correct answer is \'To allocate CPU, memory, I/O devices fairly and efficiently among processes\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#20-princípios-de-um-so" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §20 Princípios de um SO ↗</a>'],
  ['Conceitos Básicos','48','What is the primary challenge the OS faces with resource management?',['There are unlimited resources for all programs','Resources are infinite and never depleted','Processes compete for limited resources, so the OS must arbitrate fairly','Resources are only allocated once at boot time'],2,'The correct answer is \'Processes compete for limited resources, so the OS must arbitrate fairly\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#24-arranque-do-computador-boot" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §24 Arranque do Computador (Boot) ↗</a>'],
  ['Conceitos Básicos','49','Why might an OS need to prevent direct hardware access from user programs?',['To speed up hardware operations','To reduce power consumption','To protect shared resources and maintain system stability and security','To increase memory usage'],2,'The correct answer is \'To protect shared resources and maintain system stability and security\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#17-o-que-é-um-sistema-operativo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §17 O que é um Sistema Operativo? ↗</a>'],
  ['Conceitos Básicos','50','Why do different OS types have different architectural goals?',['They all have identical goals and architecture','Different environments (single user, multi-user, mobile, embedded) have different usage patterns and constraints','There is no reason; differences are random','Goals depend only on CPU speed'],1,'The correct answer is \'Different environments (single user, multi-user, mobile, embedded) have different usage patterns and constraints\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#17-o-que-é-um-sistema-operativo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §17 O que é um Sistema Operativo? ↗</a>'],
  ['Conceitos Básicos','51','What is the relationship between the kernel and system services?',['All system services are part of the kernel','Kernel is core; system services are utilities that use kernel facilities to serve applications','Services are unrelated to the kernel','The kernel runs services, which then run applications'],1,'The correct answer is \'Kernel is core; system services are utilities that use kernel facilities to serve applications\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#17-o-que-é-um-sistema-operativo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §17 O que é um Sistema Operativo? ↗</a>'],
  ['Conceitos Básicos','52','What is the purpose of firmware in the boot process?',['Firmware permanently stores application programs','Firmware runs from ROM and initializes hardware, setting up interrupt vectors before loading the kernel','Firmware manages daily backups','Firmware is the application layer'],1,'The correct answer is \'Firmware runs from ROM and initializes hardware, setting up interrupt vectors before loading the kernel\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#24-arranque-do-computador-boot" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §24 Arranque do Computador (Boot) ↗</a>'],
  ['Conceitos Básicos','53','During the boot sequence, after the kernel loads, what is the next major step?',['Applications immediately start running','The kernel initializes data structures and the init process (PID 1) is launched to start system services','The bootloader continues running','The firmware remains active'],1,'The correct answer is \'The kernel initializes data structures and the init process (PID 1) is launched to start system services\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#24-arranque-do-computador-boot" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §24 Arranque do Computador (Boot) ↗</a>'],
  ['Conceitos Básicos','54','How does the hardware enforce mode separation?',['It doesn\'t; software enforces it','A mode bit in the CPU determines which instructions are allowed','Mode is only a suggestion, not enforced','Both modes have identical access'],1,'The correct answer is \'A mode bit in the CPU determines which instructions are allowed\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#10-estruturas-struct-e-typedefs" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §10 Estruturas (struct) e Typedefs ↗</a>'],
  ['Conceitos Básicos','55','How does the OS protect one process from another?',['By running them on separate computers','By enforcing mode separation and controlling resource access through kernel','It doesn\'t; processes can interfere freely','By running them at different times'],1,'The correct answer is \'By enforcing mode separation and controlling resource access through kernel\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Conceitos Básicos','56','Why is separation of user and kernel code architecturally important?',['It provides no real benefit','It isolates the critical kernel from corruption by faulty or malicious user code, ensuring system stability','It slows down the system','It eliminates the need for security measures'],1,'The correct answer is \'It isolates the critical kernel from corruption by faulty or malicious user code, ensuring system stability\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#17-o-que-é-um-sistema-operativo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §17 O que é um Sistema Operativo? ↗</a>'],
  ['Conceitos Básicos','57','In the shell command "ls | grep .txt | sort", how many processes are created?',['One','Three (one for each command)','Two','Zero; the shell does this internally'],1,'The correct answer is \'Three (one for each command)\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#41-pipes" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §41 Pipes ↗</a>'],
  ['Conceitos Básicos','58','Why do operating systems use multitasking?',['For no reason','To share CPU among multiple processes, improving responsiveness and throughput','To slow down systems','To reduce memory usage'],1,'The correct answer is \'To share CPU among multiple processes, improving responsiveness and throughput\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#17-o-que-é-um-sistema-operativo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §17 O que é um Sistema Operativo? ↗</a>'],
  ['Conceitos Básicos','59','What is the purpose of process accounting?',['For student homework','Tracking resource usage for billing, optimization, auditing, and performance analysis','No purpose; it is optional','For administrative announcements'],1,'The correct answer is \'Tracking resource usage for billing, optimization, auditing, and performance analysis\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Conceitos Básicos','60','Can the OS measure wall-clock time?',['No; wall-clock time is external','Yes; comparing system clock at process start and end','Only if a timer is connected','Only on desktop systems'],1,'The correct answer is \'Yes; comparing system clock at process start and end\' because it accurately describes the concept.','Master concepts: Critical section, mutex, semaphore, deadlock conditions, classic problems.<br><a href="sistemas_operacoes_estudo__2_.html#69-mutex-locks" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §69 Mutex Locks ↗</a>'],
  ['Conceitos Básicos','61','How does resource limiting help OS stability?',['It doesn\'t; limits are irrelevant','By preventing a single process from consuming all available resources and starving others','By slowing down all programs','By restricting user privileges only'],1,'The correct answer is \'By preventing a single process from consuming all available resources and starving others\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Conceitos Básicos','62','What happens when a process exceeds its resource limit?',['The OS logs a warning','The OS terminates the process, typically sending a signal','The process continues unchecked','The OS slows down the process'],1,'The correct answer is \'The OS terminates the process, typically sending a signal\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Conceitos Básicos','63','What is a process group?',['A set of similar processes','A collection of related processes that can be managed together, typically all children of a shell command','All processes in the system','Processes running on the same CPU'],1,'The correct answer is \'A collection of related processes that can be managed together, typically all children of a shell command\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Conceitos Básicos','64','Why are process groups and sessions useful?',['They are not useful','They allow grouping of related processes and applying signals or I/O control to the entire group','They consume less memory','They only apply to the kernel'],1,'The correct answer is \'They allow grouping of related processes and applying signals or I/O control to the entire group\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Conceitos Básicos','65','Why might a process voluntarily give up the CPU?',['The process never voluntarily does so','The process requests I/O or waits for a resource/event','To be nice to other processes','To cool down'],1,'The correct answer is \'The process requests I/O or waits for a resource/event\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Conceitos Básicos','66','Why are pseudo-terminals needed?',['For historical compatibility','To allow remote shells, terminal multiplexing, and terminal emulators to interact with processes','They have no real purpose','Only for debugging'],1,'The correct answer is \'To allow remote shells, terminal multiplexing, and terminal emulators to interact with processes\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Conceitos Básicos','67','What is waiting time?',['Time waiting for I/O','Total time spent in READY queue waiting for CPU','Blocking time','I/O completion time'],1,'Waiting time = turnaround time - burst time. Time spent in ready queue waiting for CPU. Goal: minimize average waiting time.','Formula: Waiting = Turnaround - Burst. SJF minimizes average waiting time.<br><a href="sistemas_operacoes_estudo__2_.html#45-critérios-de-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §45 Critérios de Escalonamento ↗</a>'],
  ['Conceitos Básicos','68','What is processor binding?',['Physical attachment of CPU','Restricting a process to run on specific CPUs','CPU scheduling','Process coupling'],1,'The correct answer is \'Restricting a process to run on specific CPUs\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Conceitos Básicos','69','What is bounded waiting (third requirement)?',['Waiting for bounded time','After requesting CS, bounded number of times others can enter before this process','No waiting allowed','Waiting without limit'],1,'The correct answer is \'After requesting CS, bounded number of times others can enter before this process\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#62-os-3-requisitos-de-uma-solução" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §62 Os 3 Requisitos de uma Solução ↗</a>'],
  ['Conceitos Básicos','70','What is the cost of prevention vs. avoidance?',['Both equal','Prevention: resource waste; Avoidance: runtime overhead','Prevention cheaper','No cost difference'],1,'The correct answer is \'Prevention: resource waste; Avoidance: runtime overhead\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#17-o-que-é-um-sistema-operativo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §17 O que é um Sistema Operativo? ↗</a>'],
  ['Conceitos Básicos','71','What is the cost of detection and recovery?',['No cost','Detection: periodic overhead; Recovery: lost work from termination','Negligible cost','Unbounded cost'],1,'The correct answer is \'Detection: periodic overhead; Recovery: lost work from termination\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#17-o-que-é-um-sistema-operativo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §17 O que é um Sistema Operativo? ↗</a>'],
  ['Conceitos Básicos','72','Requiring processes to request all needed resources before starting eliminates:',['Mutual exclusion','Hold and wait','No preemption','Circular wait'],1,'If a process acquires all resources at once before executing, it never holds resources while waiting for more — eliminating the hold-and-wait condition.','Downside: poor resource utilization; possible starvation if many resources needed at once.<br><a href="sistemas_operacoes_estudo__2_.html#85-deadlock-prevention" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §85 Deadlock Prevention ↗</a>'],
  ['Conceitos Básicos','73','Which condition is effectively impossible to eliminate for truly non-shareable resources?',['Circular wait','Hold and wait','No preemption','Mutual exclusion'],3,'Mutual exclusion cannot be violated for inherently non-shareable resources (e.g., a printer genuinely cannot serve two jobs simultaneously, a file cannot have two concurrent writers without corruption).','Read-only files can be shared (eliminating mutual exclusion). Writable exclusive resources cannot.<br><a href="sistemas_operacoes_estudo__2_.html#62-os-3-requisitos-de-uma-solução" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §62 Os 3 Requisitos de uma Solução ↗</a>'],
  ['I/O e Interrupções','74','The OS arbitrates competing requests for shared resources. This describes:',['The kernel\'s role','Resource allocator/controller function','A system call interface','Device driver management'],1,'The correct answer is \'Resource allocator/controller function\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#17-o-que-é-um-sistema-operativo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §17 O que é um Sistema Operativo? ↗</a>'],
  ['I/O e Interrupções','75','What does "dual-mode operation" mean in OS context?',['Running two computers at once','Two execution modes: user (restricted) and kernel (privileged), hardware-enforced','Running both 32-bit and 64-bit programs simultaneously','Having two different operating systems'],1,'The correct answer is \'Two execution modes: user (restricted) and kernel (privileged), hardware-enforced\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#27-proteção-do-cpu-e-operação-dual-mode" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §27 Proteção do CPU e Operação Dual-Mode ↗</a>'],
  ['I/O e Interrupções','76','What is the purpose of a timer interrupt in the OS?',['To measure how fast the program runs','To force the OS to regain control from a running program and prevent monopolization','To slow down fast programs','To keep track of the current time for users'],1,'The correct answer is \'To force the OS to regain control from a running program and prevent monopolization\' because it accurately describes the concept.','Remember: Interrupt allows async I/O. CPU doesn\'t poll. Device signals when ready.<br><a href="sistemas_operacoes_estudo__2_.html#25-interrupções" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §25 Interrupções ↗</a>'],
  ['I/O e Interrupções','77','How does the OS facilitate I/O operations for programs?',['Programs must access hardware directly without OS involvement','OS handles device-specific complexity and provides uniform interface via drivers and system calls','I/O is managed entirely by hardware without OS involvement','Only privileged user programs can perform I/O'],1,'The correct answer is \'OS handles device-specific complexity and provides uniform interface via drivers and system calls\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#28-chamadas-ao-sistema-system-calls" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §28 Chamadas ao Sistema (System Calls) ↗</a>'],
  ['I/O e Interrupções','78','What is the difference between a hardware interrupt and a software interrupt (trap)?',['They are identical with no difference','Hardware: device signals CPU asynchronously; Software: program deliberately executes trap instruction','Software interrupts are faster','Hardware interrupts are only for devices'],1,'Trap = software interrupt. Deliberately causes mode switch for OS services. Hardware forces mode bit change - software cannot fake it.','Remember: Trap = software interrupt. Synchronous (program causes). Hardware interrupt = async.<br><a href="sistemas_operacoes_estudo__2_.html#25-interrupções" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §25 Interrupções ↗</a>'],
  ['I/O e Interrupções','79','When an interrupt occurs, what is the first action the CPU takes?',['Immediately jumps to the interrupt handler','Finishes the current instruction and saves the program state (PC, registers) to handle the interrupt','Restores the previous process state','Clears all memory'],1,'The correct answer is \'Finishes the current instruction and saves the program state (PC, registers) to handle the interrupt\' because it accurately describes the concept.','Remember: Interrupt allows async I/O. CPU doesn\'t poll. Device signals when ready.<br><a href="sistemas_operacoes_estudo__2_.html#25-interrupções" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §25 Interrupções ↗</a>'],
  ['I/O e Interrupções','80','What does the interrupt vector contain?',['A list of device names','Addresses of interrupt service routines, used by the CPU to find the correct handler','Memory addresses of files','List of running processes'],1,'Interrupt vector table maps interrupt numbers to handler addresses. CPU uses interrupt number as index to find handler. Fast dispatch.','Remember: Interrupt allows async I/O. CPU doesn\'t poll. Device signals when ready.<br><a href="sistemas_operacoes_estudo__2_.html#25-interrupções" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §25 Interrupções ↗</a>'],
  ['I/O e Interrupções','81','After an interrupt service routine completes, what happens?',['The system shuts down','The CPU restores the saved context and resumes the interrupted computation','The interrupt is deleted','A new interrupt is generated'],1,'The correct answer is \'The CPU restores the saved context and resumes the interrupted computation\' because it accurately describes the concept.','Remember: Interrupt allows async I/O. CPU doesn\'t poll. Device signals when ready.<br><a href="sistemas_operacoes_estudo__2_.html#25-interrupções" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §25 Interrupções ↗</a>'],
  ['I/O e Interrupções','82','Why is DMA (Direct Memory Access) useful?',['It slows down I/O operations for safety','For bulk data transfers, DMA controller handles data movement directly to RAM without CPU involvement for each byte, reducing interrupts','It is only used for printer devices','It makes keyboard input faster'],1,'DMA (Direct Memory Access) transfers large data blocks between device and memory without CPU intervention per byte. CPU initiates, DMA controller handles transfer, interrupt signals completion.','Advantage: DMA frees CPU. One interrupt per block, not per byte. Essential for high-speed I/O.<br><a href="sistemas_operacoes_estudo__2_.html#26-dispositivos-de-io-e-dma" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §26 Dispositivos de I/O e DMA ↗</a>'],
  ['I/O e Interrupções','83','How many interrupts does DMA generate?',['One per byte transferred','No interrupts at all','One per block transferred (not per byte)','Infinite interrupts'],2,'DMA allows device to transfer data directly to/from memory. CPU only involved at start/end. One interrupt per block (not per byte). Frees CPU for other work.','Advantage: DMA frees CPU. One interrupt per block, not per byte. Essential for high-speed I/O.<br><a href="sistemas_operacoes_estudo__2_.html#25-interrupções" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §25 Interrupções ↗</a>'],
  ['I/O e Interrupções','84','What is a device controller?',['A person who manages devices','Hardware that manages a specific device and exposes control registers to the OS','Software running on the device','A type of CPU cache'],1,'The correct answer is \'Hardware that manages a specific device and exposes control registers to the OS\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#26-dispositivos-de-io-e-dma" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §26 Dispositivos de I/O e DMA ↗</a>'],
  ['I/O e Interrupções','85','What role do device drivers play?',['They store files permanently','They are software that communicate with device controllers, hiding device-specific details from the OS','They manage electrical power','They control user input only'],1,'The correct answer is \'They are software that communicate with device controllers, hiding device-specific details from the OS\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#26-dispositivos-de-io-e-dma" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §26 Dispositivos de I/O e DMA ↗</a>'],
  ['I/O e Interrupções','86','What is an Interrupt Service Routine (ISR)?',['A backup copy of the interrupt vector','The code executed in response to a specific interrupt','A type of memory protection','A scheduling algorithm'],1,'The correct answer is \'The code executed in response to a specific interrupt\' because it accurately describes the concept.','Remember: Interrupt allows async I/O. CPU doesn\'t poll. Device signals when ready.<br><a href="sistemas_operacoes_estudo__2_.html#25-interrupções" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §25 Interrupções ↗</a>'],
  ['I/O e Interrupções','87','Why might the OS disable interrupts during critical operations?',['To speed up execution','To prevent interrupt handlers from interfering with atomic operations in the kernel','To save energy','Interrupts are never disabled'],1,'The correct answer is \'To prevent interrupt handlers from interfering with atomic operations in the kernel\' because it accurately describes the concept.','Remember: Interrupt allows async I/O. CPU doesn\'t poll. Device signals when ready.<br><a href="sistemas_operacoes_estudo__2_.html#25-interrupções" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §25 Interrupções ↗</a>'],
  ['I/O e Interrupções','88','What is the difference between polling and interrupts?',['Polling and interrupts are identical','Polling: CPU constantly checks devices; Interrupts: devices notify CPU when service is needed (more efficient)','Polling is more efficient than interrupts','Polling only works for keyboards'],1,'Interrupt vs polling: Interrupt - device signals CPU asynchronously, efficient. Polling - CPU repeatedly checks device, wastes cycles.','Remember: Interrupt allows async I/O. CPU doesn\'t poll. Device signals when ready.<br><a href="sistemas_operacoes_estudo__2_.html#25-interrupções" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §25 Interrupções ↗</a>'],
  ['I/O e Interrupções','89','How does the CPU identify which interrupt occurred?',['The device sends an interrupt vector number','The device name is spelled out by the interrupt signal','The CPU guesses which device interrupted','All interrupts are identical'],0,'The correct answer is \'The device sends an interrupt vector number\' because it accurately describes the concept.','Remember: Interrupt allows async I/O. CPU doesn\'t poll. Device signals when ready.<br><a href="sistemas_operacoes_estudo__2_.html#25-interrupções" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §25 Interrupções ↗</a>'],
  ['I/O e Interrupções','90','What is the purpose of the interrupt vector table?',['Lists all running processes','Maps interrupt numbers to ISR addresses so the CPU can quickly find the correct handler','Stores user passwords','Manages file systems'],1,'Interrupt vector table maps interrupt numbers to handler addresses. CPU uses interrupt number as index to find handler. Fast dispatch.','Remember: Interrupt allows async I/O. CPU doesn\'t poll. Device signals when ready.<br><a href="sistemas_operacoes_estudo__2_.html#25-interrupções" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §25 Interrupções ↗</a>'],
  ['I/O e Interrupções','91','Can an interrupt handler itself be interrupted?',['No, interrupts are never interrupted','Yes, unless interrupts are explicitly disabled','Only if the handler calls sleep()','Only for hardware interrupts'],1,'The correct answer is \'Yes, unless interrupts are explicitly disabled\' because it accurately describes the concept.','Remember: Interrupt allows async I/O. CPU doesn\'t poll. Device signals when ready.<br><a href="sistemas_operacoes_estudo__2_.html#25-interrupções" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §25 Interrupções ↗</a>'],
  ['I/O e Interrupções','92','What is a nested interrupt?',['A spiral-shaped interrupt signal','An interrupt that occurs while another interrupt handler is running','An interrupt that never completes','A type of memory corruption'],1,'The correct answer is \'An interrupt that occurs while another interrupt handler is running\' because it accurately describes the concept.','Remember: Interrupt allows async I/O. CPU doesn\'t poll. Device signals when ready.<br><a href="sistemas_operacoes_estudo__2_.html#25-interrupções" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §25 Interrupções ↗</a>'],
  ['I/O e Interrupções','93','Why is atomic execution important during interrupt handling?',['It makes programs run faster','Ensures operations cannot be partially completed or interrupted in the middle, preventing inconsistent state','It eliminates all interrupts','It increases memory usage'],1,'The correct answer is \'Ensures operations cannot be partially completed or interrupted in the middle, preventing inconsistent state\' because it accurately describes the concept.','Remember: exec does NOT create new process. Same PID, new program. Pattern: fork() then exec().<br><a href="sistemas_operacoes_estudo__2_.html#25-interrupções" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §25 Interrupções ↗</a>'],
  ['I/O e Interrupções','94','What does a timer interrupt accomplish?',['Measures wall-clock time for users','Forces the OS to regain control from the CPU from a running process at regular intervals','Synchronizes all devices','Monitors temperature sensors'],1,'The correct answer is \'Forces the OS to regain control from the CPU from a running process at regular intervals\' because it accurately describes the concept.','Remember: Interrupt allows async I/O. CPU doesn\'t poll. Device signals when ready.<br><a href="sistemas_operacoes_estudo__2_.html#25-interrupções" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §25 Interrupções ↗</a>'],
  ['I/O e Interrupções','95','How does the I/O operation flow from the perspective of DMA?',['CPU handles every byte transferred','Device driver initiates; controller transfers data directly to RAM; single interrupt when block complete','Device driver transfers data manually','DMA requires no interrupts ever'],1,'DMA (Direct Memory Access) transfers large data blocks between device and memory without CPU intervention per byte. CPU initiates, DMA controller handles transfer, interrupt signals completion.','Advantage: DMA frees CPU. One interrupt per block, not per byte. Essential for high-speed I/O.<br><a href="sistemas_operacoes_estudo__2_.html#26-dispositivos-de-io-e-dma" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §26 Dispositivos de I/O e DMA ↗</a>'],
  ['I/O e Interrupções','96','Why must I/O requests go through the OS?',['To slow down I/O operations','To prevent user programs from directly accessing devices, ensuring security and proper coordination','There is no reason; users should access hardware directly','To increase power consumption'],1,'The correct answer is \'To prevent user programs from directly accessing devices, ensuring security and proper coordination\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#25-interrupções" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §25 Interrupções ↗</a>'],
  ['I/O e Interrupções','97','What is a fault (exception)?',['An error in the program','A software interrupt triggered by an error condition detected by the CPU','A hardware failure','A type of interrupt'],1,'The correct answer is \'A software interrupt triggered by an error condition detected by the CPU\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#25-interrupções" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §25 Interrupções ↗</a>'],
  ['System Calls','98','System calls serve which purpose?',['Allow user programs to request OS kernel services safely','Only print debugging messages','Manage file permissions only','Connect to the internet'],0,'System call = controlled entry to kernel. User program cannot directly execute privileged operations. Trap instruction switches mode safely.','Remember: System call = trap instruction → kernel mode → service → user mode. Mode bit enforced by hardware.<br><a href="sistemas_operacoes_estudo__2_.html#28-chamadas-ao-sistema-system-calls" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §28 Chamadas ao Sistema (System Calls) ↗</a>'],
  ['System Calls','99','What is the main distinction between kernel mode and user mode?',['Kernel mode is for administrators only; user mode is for ordinary users','Kernel mode has full hardware access; user mode is restricted','There is no real distinction; they are the same','User mode is faster than kernel mode'],1,'Kernel mode = CPU can execute ALL instructions, access ALL memory. User mode = restricted. Mode bit in CPU controls this. System calls switch modes.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#27-proteção-do-cpu-e-operação-dual-mode" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §27 Proteção do CPU e Operação Dual-Mode ↗</a>'],
  ['System Calls','100','How do APIs improve portability compared to direct system calls?',['They are slower but more portable','They provide a standard interface so code compiles on different OS versions','They eliminate the need for system calls entirely','They only work on one operating system'],1,'System call = controlled entry to kernel. User program cannot directly execute privileged operations. Trap instruction switches mode safely.','Remember: System call = trap instruction → kernel mode → service → user mode. Mode bit enforced by hardware.<br><a href="sistemas_operacoes_estudo__2_.html#28-chamadas-ao-sistema-system-calls" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §28 Chamadas ao Sistema (System Calls) ↗</a>'],
  ['System Calls','101','Which of these is an example of a privileged instruction?',['Reading a file','Printing text to console','Modifying interrupt tables or directly controlling I/O devices','Calculating a mathematical operation'],2,'Privileged instructions (I/O, interrupt control, memory management, halt) can only execute in kernel mode. User mode attempt → trap. Protects system.','Tip: Privileged in user mode → trap. Protection mechanism. Examples: I/O, halt, interrupt control.<br><a href="sistemas_operacoes_estudo__2_.html#10-estruturas-struct-e-typedefs" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §10 Estruturas (struct) e Typedefs ↗</a>'],
  ['System Calls','102','How are system calls different from regular function calls?',['They are identical with no differences','System calls switch from user mode to kernel mode and access protected services','System calls are faster than function calls','System calls cannot pass parameters'],1,'System call = controlled entry to kernel. User program cannot directly execute privileged operations. Trap instruction switches mode safely.','Remember: System call = trap instruction → kernel mode → service → user mode. Mode bit enforced by hardware.<br><a href="sistemas_operacoes_estudo__2_.html#28-chamadas-ao-sistema-system-calls" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §28 Chamadas ao Sistema (System Calls) ↗</a>'],
  ['System Calls','103','What is kernel mode?',['A slow mode used for system startup','Privileged execution mode where the OS kernel can access all hardware and memory','Only for administrator accounts','A debugging mode'],1,'Kernel mode = CPU can execute ALL instructions, access ALL memory. User mode = restricted. Mode bit in CPU controls this. System calls switch modes.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#27-proteção-do-cpu-e-operação-dual-mode" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §27 Proteção do CPU e Operação Dual-Mode ↗</a>'],
  ['System Calls','104','What happens when user-mode code attempts a privileged instruction?',['The instruction executes normally','The CPU generates a trap, switching to kernel mode for the OS to handle it','The program is deleted','Nothing happens'],1,'Privileged instructions (I/O, interrupt control, memory management, halt) can only execute in kernel mode. User mode attempt → trap. Protects system.','Tip: Privileged in user mode → trap. Protection mechanism. Examples: I/O, halt, interrupt control.<br><a href="sistemas_operacoes_estudo__2_.html#10-estruturas-struct-e-typedefs" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §10 Estruturas (struct) e Typedefs ↗</a>'],
  ['System Calls','105','How does a system call transition from user to kernel mode?',['It requests permission from the user','The user program executes a trap instruction, which hardware automatically switches mode','The program manually changes the mode bit','System calls never change modes'],1,'System call sequence: (1) User program executes trap/int instruction, (2) Hardware switches to kernel mode, (3) Jump to syscall handler via vector, (4) Execute service, (5) Return to user mode.','Remember: System call = trap instruction → kernel mode → service → user mode. Mode bit enforced by hardware.<br><a href="sistemas_operacoes_estudo__2_.html#27-proteção-do-cpu-e-operação-dual-mode" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §27 Proteção do CPU e Operação Dual-Mode ↗</a>'],
  ['System Calls','106','Which of the following is NOT a system call category?',['File manipulation','Process control','Printing greeting messages','Device manipulation'],2,'System call = controlled entry to kernel. User program cannot directly execute privileged operations. Trap instruction switches mode safely.','Remember: System call = trap instruction → kernel mode → service → user mode. Mode bit enforced by hardware.<br><a href="sistemas_operacoes_estudo__2_.html#28-chamadas-ao-sistema-system-calls" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §28 Chamadas ao Sistema (System Calls) ↗</a>'],
  ['System Calls','107','What is the purpose of the trap instruction?',['To catch errors in user programs','To deliberately cause a controlled mode switch from user to kernel for OS services','To prevent interrupts','To access files only'],1,'Trap = software interrupt. Deliberately causes mode switch for OS services. Hardware forces mode bit change - software cannot fake it.','Remember: Trap = software interrupt. Synchronous (program causes). Hardware interrupt = async.<br><a href="sistemas_operacoes_estudo__2_.html#10-estruturas-struct-e-typedefs" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §10 Estruturas (struct) e Typedefs ↗</a>'],
  ['System Calls','108','How do APIs differ from system calls?',['They are identical','APIs provide a standard, portable interface; system calls are OS-specific and lower-level','System calls are used by programmers; APIs are not','APIs are slower than system calls'],1,'System call = controlled entry to kernel. User program cannot directly execute privileged operations. Trap instruction switches mode safely.','Remember: System call = trap instruction → kernel mode → service → user mode. Mode bit enforced by hardware.<br><a href="sistemas_operacoes_estudo__2_.html#28-chamadas-ao-sistema-system-calls" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §28 Chamadas ao Sistema (System Calls) ↗</a>'],
  ['System Calls','109','What is the Win32 API?',['A Unix standard','The Windows operating system','The standard API for requesting Windows kernel services','A programming language'],2,'The correct answer is \'The standard API for requesting Windows kernel services\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#28-chamadas-ao-sistema-system-calls" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §28 Chamadas ao Sistema (System Calls) ↗</a>'],
  ['System Calls','110','How does the Java API enable cross-platform compatibility?',['Java programs run directly on the OS','The JVM translates Java calls to native OS calls, allowing code to run on any system with a JVM','Java eliminates the need for an OS','Java can only run on Windows'],1,'The correct answer is \'The JVM translates Java calls to native OS calls, allowing code to run on any system with a JVM\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#28-chamadas-ao-sistema-system-calls" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §28 Chamadas ao Sistema (System Calls) ↗</a>'],
  ['System Calls','111','Why might a program use an API instead of direct system calls?',['For better portability, error handling, and additional functionality provided by the API','System calls are always faster','APIs are lower-level than system calls','No advantage; they are identical'],0,'System call = controlled entry to kernel. User program cannot directly execute privileged operations. Trap instruction switches mode safely.','Remember: System call = trap instruction → kernel mode → service → user mode. Mode bit enforced by hardware.<br><a href="sistemas_operacoes_estudo__2_.html#28-chamadas-ao-sistema-system-calls" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §28 Chamadas ao Sistema (System Calls) ↗</a>'],
  ['System Calls','112','What is the relationship between a system call and an interrupt?',['They are completely unrelated','A system call is a software interrupt (trap) that transitions to kernel mode','Interrupts are system calls','System calls prevent interrupts'],1,'System call = controlled entry to kernel. User program cannot directly execute privileged operations. Trap instruction switches mode safely.','Remember: System call = trap instruction → kernel mode → service → user mode. Mode bit enforced by hardware.<br><a href="sistemas_operacoes_estudo__2_.html#25-interrupções" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §25 Interrupções ↗</a>'],
  ['System Calls','113','How does the kernel identify which system call was requested?',['The program name is passed as a parameter','The system call number is placed in a CPU register by the calling program','The OS guesses which service is needed','All system calls perform the same operation'],1,'System call = controlled entry to kernel. User program cannot directly execute privileged operations. Trap instruction switches mode safely.','Remember: System call = trap instruction → kernel mode → service → user mode. Mode bit enforced by hardware.<br><a href="sistemas_operacoes_estudo__2_.html#28-chamadas-ao-sistema-system-calls" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §28 Chamadas ao Sistema (System Calls) ↗</a>'],
  ['System Calls','114','What happens after a system call completes?',['The program terminates','The kernel returns to the user program, restoring mode bit to user mode and resuming execution','Another system call is automatically made','The process switches to a different program'],1,'System call = controlled entry to kernel. User program cannot directly execute privileged operations. Trap instruction switches mode safely.','Remember: System call = trap instruction → kernel mode → service → user mode. Mode bit enforced by hardware.<br><a href="sistemas_operacoes_estudo__2_.html#28-chamadas-ao-sistema-system-calls" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §28 Chamadas ao Sistema (System Calls) ↗</a>'],
  ['System Calls','115','Why is the trap instruction necessary for system calls?',['To prevent programs from running','Hardware-supported trap ensures atomicity and forces mode switch; software cannot fake mode changes','To slow down the system','It is not necessary; programs could change mode manually'],1,'System call = controlled entry to kernel. User program cannot directly execute privileged operations. Trap instruction switches mode safely.','Remember: System call = trap instruction → kernel mode → service → user mode. Mode bit enforced by hardware.<br><a href="sistemas_operacoes_estudo__2_.html#10-estruturas-struct-e-typedefs" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §10 Estruturas (struct) e Typedefs ↗</a>'],
  ['System Calls','116','What is the cost of switching between user and kernel mode?',['No cost; it is free','Small overhead for flushing CPU caches and reloading translation lookaside buffers','Infinite cost; mode switching is impossible','Only the time to execute one instruction'],1,'Kernel mode = CPU can execute ALL instructions, access ALL memory. User mode = restricted. Mode bit in CPU controls this. System calls switch modes.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#4-estruturas-de-decisão-e-ciclos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §4 Estruturas de Decisão e Ciclos ↗</a>'],
  ['System Calls','117','What is the syscall dispatcher?',['A device that dispatches commands to hardware','Kernel code that looks up the system call number in a table and invokes the correct handler','A process scheduler','A type of interrupt handler'],1,'The correct answer is \'Kernel code that looks up the system call number in a table and invokes the correct handler\' because it accurately describes the concept.','Study all algorithms: FCFS, SJF, SRTF, RR, Priority, MLFQ. Know metrics: waiting, turnaround, response.<br><a href="sistemas_operacoes_estudo__2_.html#28-chamadas-ao-sistema-system-calls" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §28 Chamadas ao Sistema (System Calls) ↗</a>'],
  ['Processos','118','Which OS service prevents processes from interfering with each other?',['Error detection','Protection and security','Accounting','Program execution'],1,'The correct answer is \'Protection and security\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#22-serviços-comuns-de-um-so" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §22 Serviços Comuns de um SO ↗</a>'],
  ['Processos','119','Which best describes the relationship between hardware and the OS?',['Hardware and OS are independent with no interaction','OS sits between hardware and programs, controlling and hiding hardware complexity','Hardware controls the OS','OS is part of the hardware itself'],1,'The correct answer is \'OS sits between hardware and programs, controlling and hiding hardware complexity\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#19-estrutura-de-um-sistema-computacional" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §19 Estrutura de um Sistema Computacional ↗</a>'],
  ['Processos','120','What is the significance of the OS sitting "between" programs and hardware?',['It is merely a storage location','It manages access, hides hardware complexity, enforces security, and coordinates resource sharing','It slows down all operations','It prevents hardware and software from functioning together'],1,'The correct answer is \'It manages access, hides hardware complexity, enforces security, and coordinates resource sharing\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#19-estrutura-de-um-sistema-computacional" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §19 Estrutura de um Sistema Computacional ↗</a>'],
  ['Processos','121','Why is abstraction important in OS design?',['It makes the OS more complicated','It hides hardware complexity and presents simpler interfaces so programmers don\'t need hardware expertise','It requires more memory','It eliminates the need for hardware'],1,'The correct answer is \'It hides hardware complexity and presents simpler interfaces so programmers don\'t need hardware expertise\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Processos','122','What is saved in the PCB during a context switch triggered by an interrupt?',['Only the program counter','All CPU registers, program counter, stack pointer, and memory management info','Nothing is saved','Only memory addresses'],1,'PCB stores all info the OS needs to manage a process: PID, state, PC, registers, memory limits, scheduling info, I/O status, accounting. Essential for context switching.','EXAM TIP: Context switch = pure overhead (no useful work). Goal: minimize frequency.<br><a href="sistemas_operacoes_estudo__2_.html#4-estruturas-de-decisão-e-ciclos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §4 Estruturas de Decisão e Ciclos ↗</a>'],
  ['Processos','123','Can user-mode code execute I/O instructions?',['Yes, without restrictions','No; I/O instructions are privileged and cause a trap if attempted in user mode','Only if the user is administrator','Only for read operations'],1,'The correct answer is \'No; I/O instructions are privileged and cause a trap if attempted in user mode\' because it accurately describes the concept.','Remember: exec does NOT create new process. Same PID, new program. Pattern: fork() then exec().<br><a href="sistemas_operacoes_estudo__2_.html#10-estruturas-struct-e-typedefs" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §10 Estruturas (struct) e Typedefs ↗</a>'],
  ['Processos','124','What information does a Process Control Block (PCB) contain?',['Only the program code','Process state, PID, program counter, CPU registers, scheduling info, memory info, I/O state, and accounting info','Only the process name','Just the file location'],1,'PCB stores all info the OS needs to manage a process: PID, state, PC, registers, memory limits, scheduling info, I/O status, accounting. Essential for context switching.','Remember: PCB = process passport. Contains everything OS needs to manage/restart process.<br><a href="sistemas_operacoes_estudo__2_.html#30-process-control-block-pcb" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §30 Process Control Block (PCB) ↗</a>'],
  ['Processos','125','What is the purpose of a PCB?',['To store the executable code','To maintain all information the OS needs to manage and context switch the process','To track user login times','To store passwords'],1,'PCB stores all info the OS needs to manage a process: PID, state, PC, registers, memory limits, scheduling info, I/O status, accounting. Essential for context switching.','Remember: PCB = process passport. Contains everything OS needs to manage/restart process.<br><a href="sistemas_operacoes_estudo__2_.html#30-process-control-block-pcb" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §30 Process Control Block (PCB) ↗</a>'],
  ['Processos','126','List the five main process states in order:',['Ready, Running, Waiting, New, Terminated','New, Ready, Running, Waiting, Terminated','Running, Ready, Waiting, New, Terminated','Terminated, Running, Ready, Waiting, New'],1,'5 process states: New (being created) → Ready (waiting for CPU) → Running (executing) → Waiting (I/O) → Terminated. Scheduler moves between Ready ↔ Running.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#30-process-control-block-pcb" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §30 Process Control Block (PCB) ↗</a>'],
  ['Processos','127','What does the NEW state mean?',['The process is actively running','The process is waiting for I/O','The process is being created; PCB is allocated but not yet admitted to ready queue','The process has finished'],2,'The correct answer is \'The process is being created; PCB is allocated but not yet admitted to ready queue\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#32-estados-de-um-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §32 Estados de um Processo ↗</a>'],
  ['Processos','128','What does the READY state mean?',['All resources are ready, but the process has CPU access','All necessary resources are available, but the process waits for CPU scheduler','The process is actively executing','The process is waiting for a device'],1,'The correct answer is \'All necessary resources are available, but the process waits for CPU scheduler\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#32-estados-de-um-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §32 Estados de um Processo ↗</a>'],
  ['Processos','129','What does the RUNNING state mean?',['The process is waiting for I/O','The process is ready and waiting','The process is actively executing on the CPU','The process has exited'],2,'The correct answer is \'The process is actively executing on the CPU\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#32-estados-de-um-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §32 Estados de um Processo ↗</a>'],
  ['Processos','130','What does the WAITING state mean?',['The process is running','The process is paused, waiting for an I/O event, signal, or resource','The process is ready to run','The process is being created'],1,'The correct answer is \'The process is paused, waiting for an I/O event, signal, or resource\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#32-estados-de-um-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §32 Estados de um Processo ↗</a>'],
  ['Processos','131','What does the TERMINATED state mean?',['The process is running normally','The process has exited; cleanup is in progress','The process is suspended','The process just entered the system'],1,'The correct answer is \'The process has exited; cleanup is in progress\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#32-estados-de-um-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §32 Estados de um Processo ↗</a>'],
  ['Processos','132','What causes a transition from RUNNING to READY?',['An I/O request','A timer interrupt fires; the process\'s time quantum expires','The process completes','A signal is sent to the process'],1,'The correct answer is \'A timer interrupt fires; the process\'s time quantum expires\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#33-transições-entre-estados" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §33 Transições entre Estados ↗</a>'],
  ['Processos','133','What causes a transition from RUNNING to WAITING?',['End of time quantum','The process voluntarily requests I/O or waits for a resource','The scheduler decides to preempt','The process exits'],1,'The correct answer is \'The process voluntarily requests I/O or waits for a resource\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#33-transições-entre-estados" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §33 Transições entre Estados ↗</a>'],
  ['Processos','134','What causes a transition from WAITING to READY?',['Timer interrupt','The I/O completes, signal is received, or resource becomes available','Process explicitly requests it','Scheduler makes the decision'],1,'The correct answer is \'The I/O completes, signal is received, or resource becomes available\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#33-transições-entre-estados" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §33 Transições entre Estados ↗</a>'],
  ['Processos','135','Why can\'t a process go directly from WAITING to RUNNING?',['It can go directly','Another process might have higher priority; the scheduler must decide after I/O completion','Waiting is a terminal state','The process must call exit() first'],1,'The correct answer is \'Another process might have higher priority; the scheduler must decide after I/O completion\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Processos','136','What is the process memory layout (from high to low address)?',['Text, Data, Heap, Stack','Stack, (gap), Heap, Data, Text','Data, Heap, Stack, Text','Stack, Heap, Data, Text'],1,'The correct answer is \'Stack, (gap), Heap, Data, Text\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Processos','137','What is the TEXT segment?',['Text files stored by the process','Read-only compiled instructions; shareable between multiple processes running the same program','Dynamic memory allocated by malloc','The program\'s strings and messages'],1,'The correct answer is \'Read-only compiled instructions; shareable between multiple processes running the same program\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#9-alocação-dinâmica-de-memória" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §9 Alocação Dinâmica de Memória ↗</a>'],
  ['Processos','138','What is the DATA segment?',['User input data','Initialized and uninitialized global/static variables','Memory allocated at runtime','The program stack'],1,'The correct answer is \'Initialized and uninitialized global/static variables\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Processos','139','What is the STACK?',['A data structure used to store variables','Memory for function frames, local variables, return addresses; grows downward toward heap','The heap in a different order','Permanent storage'],1,'The correct answer is \'Memory for function frames, local variables, return addresses; grows downward toward heap\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#10-estruturas-struct-e-typedefs" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §10 Estruturas (struct) e Typedefs ↗</a>'],
  ['Processos','140','Why are TEXT segments shared between processes?',['They are never shared','Read-only code can be safely shared, saving memory','Sharing is dangerous','It increases performance'],1,'The correct answer is \'Read-only code can be safely shared, saving memory\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Processos','141','Why is the DATA segment private to each process?',['For no particular reason','Global/static variables must be private; sharing would cause data corruption','The OS forbids sharing','Data cannot be stored otherwise'],1,'The correct answer is \'Global/static variables must be private; sharing would cause data corruption\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Processos','142','What is context switching?',['Changing the priority of a process','Saving current process state, loading another process\'s state, and transferring CPU control','Moving a process from one computer to another','Deleting a process\'s context'],1,'Context switch = saving current process state to PCB, loading another process state from PCB, and transferring CPU control. Triggered by timer interrupt or process blocking.','EXAM TIP: Context switch = pure overhead (no useful work). Goal: minimize frequency.<br><a href="sistemas_operacoes_estudo__2_.html#4-estruturas-de-decisão-e-ciclos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §4 Estruturas de Decisão e Ciclos ↗</a>'],
  ['Processos','143','What must be saved during a context switch?',['Only the program counter','All CPU registers, program counter, stack pointer, and memory management info','Only the process name','Nothing needs to be saved'],1,'Context switch = saving current process state to PCB, loading another process state from PCB, and transferring CPU control. Triggered by timer interrupt or process blocking.','EXAM TIP: Context switch = pure overhead (no useful work). Goal: minimize frequency.<br><a href="sistemas_operacoes_estudo__2_.html#4-estruturas-de-decisão-e-ciclos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §4 Estruturas de Decisão e Ciclos ↗</a>'],
  ['Processos','144','Why is context switch overhead significant?',['It is not significant','Too many context switches reduce CPU time for useful work','It makes all programs run backwards','It increases memory dramatically'],1,'Context switch = saving current process state to PCB, loading another process state from PCB, and transferring CPU control. Triggered by timer interrupt or process blocking.','EXAM TIP: Context switch = pure overhead (no useful work). Goal: minimize frequency.<br><a href="sistemas_operacoes_estudo__2_.html#4-estruturas-de-decisão-e-ciclos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §4 Estruturas de Decisão e Ciclos ↗</a>'],
  ['Processos','145','What is fork()?',['A command to terminate a process','A Unix system call that creates a child process as an exact copy of the parent','A way to combine two processes','A process communication method'],1,'fork() creates a child process that\'s an exact copy of parent. Memory, file descriptors, registers duplicated. Child and parent execute independently from return of fork().','Mnemonic: fork = \'split\' process. Child is exact copy at that moment. Both run independently after.<br><a href="sistemas_operacoes_estudo__2_.html#37-fork-e-exec-em-unixlinux" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §37 fork() e exec() em UNIX/Linux ↗</a>'],
  ['Processos','146','What value does fork() return to the child?',['The parent\'s PID','Zero (0)','The child\'s PID','-1 (error)'],1,'fork() returns TWICE: returns 0 to child process, returns child\'s PID to parent, returns -1 on error. Child is exact copy of parent at fork() point.','CRITICAL: fork() returns 0 to child, child PID to parent, -1 on error. Both continue execution.<br><a href="sistemas_operacoes_estudo__2_.html#37-fork-e-exec-em-unixlinux" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §37 fork() e exec() em UNIX/Linux ↗</a>'],
  ['Processos','147','What value does fork() return to the parent?',['Zero (0)','The child\'s PID','Its own PID','Undefined'],1,'fork() creates a child process that\'s an exact copy of parent. Memory, file descriptors, registers duplicated. Child and parent execute independently from return of fork().','CRITICAL: fork() returns 0 to child, child PID to parent, -1 on error. Both continue execution.<br><a href="sistemas_operacoes_estudo__2_.html#37-fork-e-exec-em-unixlinux" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §37 fork() e exec() em UNIX/Linux ↗</a>'],
  ['Processos','148','What is exec()?',['A system call that terminates the current process','A system call that replaces the process\'s program with a new program; PID unchanged','A system call that creates a new process','A way to run a program in background'],1,'exec() family (execl, execv, execvp) replaces current process image with new program. Same PID, different code/data. Common pattern: fork() then exec().','Remember: exec does NOT create new process. Same PID, new program. Pattern: fork() then exec().<br><a href="sistemas_operacoes_estudo__2_.html#37-fork-e-exec-em-unixlinux" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §37 fork() e exec() em UNIX/Linux ↗</a>'],
  ['Processos','149','Does exec() create a new process?',['Yes; a new process is always created','No; it replaces the current process\'s image with new code','Sometimes, depending on the parameter','Only on some operating systems'],1,'exec() does NOT create new process. It replaces current process\'s memory/code with new program. PID unchanged. Often follows fork() to run different program.','Remember: exec does NOT create new process. Same PID, new program. Pattern: fork() then exec().<br><a href="sistemas_operacoes_estudo__2_.html#37-fork-e-exec-em-unixlinux" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §37 fork() e exec() em UNIX/Linux ↗</a>'],
  ['Processos','150','What is exit()?',['A system call that pauses a process','A system call that terminates the calling process and releases all resources','A system call that switches processes','A system call that returns to the parent'],1,'exit() terminates calling process and releases resources. Returns exit status to parent. If parent hasn\'t called wait(), child becomes zombie.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#38-terminação-de-processos-exit-wait-zombie-orphan" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §38 Terminação de Processos (exit, wait, zombie, orphan) ↗</a>'],
  ['Processos','151','What is wait()?',['A system call that pauses the CPU','A system call where the parent blocks until a child terminates','A system call that creates a new process','A system call that exits the process'],1,'wait() blocks parent until any child terminates. Returns terminated child\'s PID. Prevents zombie accumulation. waitpid() can wait for specific child.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#38-terminação-de-processos-exit-wait-zombie-orphan" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §38 Terminação de Processos (exit, wait, zombie, orphan) ↗</a>'],
  ['Processos','152','Why should a parent call wait()?',['To speed up the child','To prevent zombie processes from accumulating in the process table','To create a new child','To run the child faster'],1,'wait() blocks parent until any child terminates. Returns terminated child\'s PID. Prevents zombie accumulation. waitpid() can wait for specific child.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#38-terminação-de-processos-exit-wait-zombie-orphan" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §38 Terminação de Processos (exit, wait, zombie, orphan) ↗</a>'],
  ['Processos','153','What is a zombie process?',['A process that runs in the background','A terminated process whose parent has not yet called wait(); PCB remains in the table','A process that is waiting for I/O','A process running at low priority'],1,'Zombie process has terminated (exit() called) but parent hasn\'t called wait() yet. PCB remains in table to store exit status. Not dangerous but wastes space.','Mnemonic: Zombie = dead but not buried. Parent must call wait() to clean up (reap) zombie.<br><a href="sistemas_operacoes_estudo__2_.html#38-terminação-de-processos-exit-wait-zombie-orphan" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §38 Terminação de Processos (exit, wait, zombie, orphan) ↗</a>'],
  ['Processos','154','What is an orphan process?',['A process that has no children','A process whose parent terminated before calling wait() on it','A process that is not yet started','A process that is about to crash'],1,'Orphan process\'s parent terminated before it. Init process (PID 1) automatically adopts all orphans and cleans them up when they terminate.','Remember: Orphan adopted by init/systemd (PID 1). Init periodically reaps them. No zombie problem.<br><a href="sistemas_operacoes_estudo__2_.html#38-terminação-de-processos-exit-wait-zombie-orphan" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §38 Terminação de Processos (exit, wait, zombie, orphan) ↗</a>'],
  ['Processos','155','Who reaps orphan processes on Unix/Linux?',['The OS kernel','init (PID 1) or systemd automatically adopts and periodically waits on orphans','A special daemon process','Orphans are never reaped'],1,'When parent dies before child, init (PID 1) or systemd adopts orphans and periodically calls wait() to reap them. Prevents orphans from becoming zombies.','Remember: Orphan adopted by init/systemd (PID 1). Init periodically reaps them. No zombie problem.<br><a href="sistemas_operacoes_estudo__2_.html#38-terminação-de-processos-exit-wait-zombie-orphan" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §38 Terminação de Processos (exit, wait, zombie, orphan) ↗</a>'],
  ['Processos','156','Why are pipes commonly created before fork()?',['For efficiency','So the child process inherits the pipe file descriptors, enabling parent-child communication','Pipes cannot work after fork()','For security reasons'],1,'fork() creates a child process that\'s an exact copy of parent. Memory, file descriptors, registers duplicated. Child and parent execute independently from return of fork().','Mnemonic: fork = \'split\' process. Child is exact copy at that moment. Both run independently after.<br><a href="sistemas_operacoes_estudo__2_.html#37-fork-e-exec-em-unixlinux" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §37 fork() e exec() em UNIX/Linux ↗</a>'],
  ['Processos','157','What is the relationship between process creation and context switching?',['They are unrelated','Creating a new process involves context switching to initialize it and later switch back','Context switching creates new processes','They cannot happen together'],1,'Context switch = saving current process state to PCB, loading another process state from PCB, and transferring CPU control. Triggered by timer interrupt or process blocking.','EXAM TIP: Context switch = pure overhead (no useful work). Goal: minimize frequency.<br><a href="sistemas_operacoes_estudo__2_.html#4-estruturas-de-decisão-e-ciclos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §4 Estruturas de Decisão e Ciclos ↗</a>'],
  ['Processos','158','Why might a process need to create child processes?',['No particular reason','For modularity, parallelism, or to run external programs with isolation','To consume more memory','To slow down execution'],1,'The correct answer is \'For modularity, parallelism, or to run external programs with isolation\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#35-criação-de-processos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §35 Criação de Processos ↗</a>'],
  ['Processos','159','What is the relationship between process and address space?',['They are unrelated','Each process has its own isolated address space','All processes share one address space','Address space can change during execution'],1,'The correct answer is \'Each process has its own isolated address space\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Processos','160','Why is each process\'s address space isolated?',['For efficiency','To protect processes from interfering with each other; isolation prevents corruption','To reduce memory usage','For speed'],1,'The correct answer is \'To protect processes from interfering with each other; isolation prevents corruption\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Processos','161','What happens when a process accesses invalid memory?',['The access succeeds silently','The OS detects the fault and terminates the process','The kernel executes the access anyway','Memory is dynamically allocated'],1,'The correct answer is \'The OS detects the fault and terminates the process\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Processos','162','What is process lifetime management?',['Creating a calendar of process events','The OS managing process creation, execution, and termination','Killing processes manually','A user-level activity'],1,'The correct answer is \'The OS managing process creation, execution, and termination\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Processos','163','How is a process\'s resource utilization tracked?',['It is not tracked','The PCB maintains accounting info: CPU time, wall-clock time, memory, I/O usage, etc.','Only the kernel knows','By examining the program code'],1,'The correct answer is \'The PCB maintains accounting info: CPU time, wall-clock time, memory, I/O usage, etc.\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Processos','164','Can the OS measure actual CPU time used by a process?',['No; CPU time is immeasurable','Yes; using timers and context switch logs','Only if the program explicitly reports it','Only on some systems'],1,'The correct answer is \'Yes; using timers and context switch logs\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Processos','165','Can a parent process restart a terminated child?',['No; terminated processes cannot be restarted','The parent would need to fork() another child; the same process cannot be restarted','Only if the child saved its state','Yes; any process can be restarted'],1,'The correct answer is \'The parent would need to fork() another child; the same process cannot be restarted\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Processos','166','What is process spawning?',['The process of eggs hatching','The OS act of creating a new process','The process exiting','The process moving to a different machine'],1,'The correct answer is \'The OS act of creating a new process\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Processos','167','What happens if fork() fails?',['The system crashes','fork() returns -1 to the parent; no child is created','A child is created without a parent','The parent terminates'],1,'fork() creates a child process that\'s an exact copy of parent. Memory, file descriptors, registers duplicated. Child and parent execute independently from return of fork().','Mnemonic: fork = \'split\' process. Child is exact copy at that moment. Both run independently after.<br><a href="sistemas_operacoes_estudo__2_.html#37-fork-e-exec-em-unixlinux" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §37 fork() e exec() em UNIX/Linux ↗</a>'],
  ['Processos','168','What are the common causes of fork() failure?',['Never fails','System resource exhaustion (max processes reached, insufficient memory)','User error only','fork() always succeeds'],1,'fork() creates a child process that\'s an exact copy of parent. Memory, file descriptors, registers duplicated. Child and parent execute independently from return of fork().','Mnemonic: fork = \'split\' process. Child is exact copy at that moment. Both run independently after.<br><a href="sistemas_operacoes_estudo__2_.html#37-fork-e-exec-em-unixlinux" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §37 fork() e exec() em UNIX/Linux ↗</a>'],
  ['Processos','169','What is a daemon process?',['A malicious process','A background system process typically started at boot and running without user interaction','A special user account','A type of interrupt handler'],1,'The correct answer is \'A background system process typically started at boot and running without user interaction\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Processos','170','What is a zombie state in more detail?',['A process completely removed from the system','Process has exited but PCB remains in table until parent calls wait(); parent must clean it up','A process that is very slow','A process running background code'],1,'Zombie process has terminated (exit() called) but parent hasn\'t called wait() yet. PCB remains in table to store exit status. Not dangerous but wastes space.','Mnemonic: Zombie = dead but not buried. Parent must call wait() to clean up (reap) zombie.<br><a href="sistemas_operacoes_estudo__2_.html#38-terminação-de-processos-exit-wait-zombie-orphan" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §38 Terminação de Processos (exit, wait, zombie, orphan) ↗</a>'],
  ['Processos','171','Why don\'t zombies immediately disappear?',['They cannot disappear','Parent might need exit status; kernel waits for parent to call wait() to reap the process','Zombies are permanent','The system decides to keep them'],1,'Zombie accumulation wastes process table slots. Parent must call wait() to reap zombies. If parent never waits, zombies persist until parent dies.','Mnemonic: Zombie = dead but not buried. Parent must call wait() to clean up (reap) zombie.<br><a href="sistemas_operacoes_estudo__2_.html#38-terminação-de-processos-exit-wait-zombie-orphan" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §38 Terminação de Processos (exit, wait, zombie, orphan) ↗</a>'],
  ['Processos','172','What is the maximum number of zombie processes?',['Zero; no zombie can exist','Theoretically unlimited if the parent doesn\'t call wait(), limited by process table size','Always one','Depends on RAM'],1,'Zombie process has terminated (exit() called) but parent hasn\'t called wait() yet. PCB remains in table to store exit status. Not dangerous but wastes space.','Mnemonic: Zombie = dead but not buried. Parent must call wait() to clean up (reap) zombie.<br><a href="sistemas_operacoes_estudo__2_.html#38-terminação-de-processos-exit-wait-zombie-orphan" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §38 Terminação de Processos (exit, wait, zombie, orphan) ↗</a>'],
  ['Processos','173','How would you fix a zombie process?',['Reboot the system','Kill the parent process so the zombie is adopted by init, which will reap it','Zombies cannot be fixed','Run a cleanup program'],1,'Zombie process has terminated (exit() called) but parent hasn\'t called wait() yet. PCB remains in table to store exit status. Not dangerous but wastes space.','Mnemonic: Zombie = dead but not buried. Parent must call wait() to clean up (reap) zombie.<br><a href="sistemas_operacoes_estudo__2_.html#38-terminação-de-processos-exit-wait-zombie-orphan" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §38 Terminação de Processos (exit, wait, zombie, orphan) ↗</a>'],
  ['Processos','174','What is process priority?',['How important the process code is','A value determining when the scheduler selects a process relative to others','A user preference','A static property set at compilation'],1,'Priority Scheduling runs highest priority process first. Can be preemptive or non-preemptive. Problem: starvation of low-priority processes. Solution: aging.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Processos','175','What is a context switch trigger?',['An event that should trigger a context switch','Scheduler decision points including: time quantum expiration, I/O request, process exit, or higher priority arrival','An instruction in the process code','A user command'],1,'Context switch = saving current process state to PCB, loading another process state from PCB, and transferring CPU control. Triggered by timer interrupt or process blocking.','EXAM TIP: Context switch = pure overhead (no useful work). Goal: minimize frequency.<br><a href="sistemas_operacoes_estudo__2_.html#4-estruturas-de-decisão-e-ciclos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §4 Estruturas de Decisão e Ciclos ↗</a>'],
  ['Processos','176','Can a context switch occur while a process is executing a system call?',['No; system calls prevent switching','Yes; the OS can preempt and switch while in kernel mode if needed','Only if the system call blocks on I/O','Never in modern systems'],1,'Context switch = saving current process state to PCB, loading another process state from PCB, and transferring CPU control. Triggered by timer interrupt or process blocking.','Remember: exec does NOT create new process. Same PID, new program. Pattern: fork() then exec().<br><a href="sistemas_operacoes_estudo__2_.html#4-estruturas-de-decisão-e-ciclos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §4 Estruturas de Decisão e Ciclos ↗</a>'],
  ['Processos','177','What is the relationship between process state and scheduling?',['Unrelated','Only READY processes are scheduled to run; transitions between states depend on scheduling events','Process state is independent of scheduling','All states can be scheduled equally'],1,'5 process states: New (being created) → Ready (waiting for CPU) → Running (executing) → Waiting (I/O) → Terminated. Scheduler moves between Ready ↔ Running.','Study all algorithms: FCFS, SJF, SRTF, RR, Priority, MLFQ. Know metrics: waiting, turnaround, response.<br><a href="sistemas_operacoes_estudo__2_.html#30-process-control-block-pcb" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §30 Process Control Block (PCB) ↗</a>'],
  ['Processos','178','What is the difference between a foreground and background process?',['Only color-related','Foreground has terminal control/waits for user input; background runs without terminal interaction','Background is always lower priority','Only applicable to GUI systems'],1,'The correct answer is \'Foreground has terminal control/waits for user input; background runs without terminal interaction\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Processos','179','How does a shell implement background process execution?',['By starting a new shell','By not calling wait() on the child process, allowing the parent shell to continue immediately','By putting the process on a different computer','Shells cannot run background processes'],1,'The correct answer is \'By not calling wait() on the child process, allowing the parent shell to continue immediately\' because it accurately describes the concept.','Remember: exec does NOT create new process. Same PID, new program. Pattern: fork() then exec().<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Processos','180','Why are pipes often created before fork()?',['For efficiency','So the parent and child both inherit the pipe file descriptors, enabling communication','Pipes must be created before fork','To avoid blocking'],1,'fork() creates a child process that\'s an exact copy of parent. Memory, file descriptors, registers duplicated. Child and parent execute independently from return of fork().','Mnemonic: fork = \'split\' process. Child is exact copy at that moment. Both run independently after.<br><a href="sistemas_operacoes_estudo__2_.html#37-fork-e-exec-em-unixlinux" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §37 fork() e exec() em UNIX/Linux ↗</a>'],
  ['Processos','181','What is the main advantage of RR?',['Optimal response time','Fair CPU allocation; good response time for interactive systems','Eliminates context switches','Prevents all starvation'],1,'The correct answer is \'Fair CPU allocation; good response time for interactive systems\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#4-estruturas-de-decisão-e-ciclos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §4 Estruturas de Decisão e Ciclos ↗</a>'],
  ['Processos','182','What is the main disadvantage of RR?',['Unfair to short processes','Context switch overhead; larger quantum may increase wait time','Cannot handle I/O','Too simple'],1,'The correct answer is \'Context switch overhead; larger quantum may increase wait time\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#4-estruturas-de-decisão-e-ciclos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §4 Estruturas de Decisão e Ciclos ↗</a>'],
  ['Processos','183','When does excessive context switching occur?',['When processes cooperate','When time quantum is too small or too many processes; reduces efficiency','With preemptive scheduling always','With large quantum'],1,'Context switch = saving current process state to PCB, loading another process state from PCB, and transferring CPU control. Triggered by timer interrupt or process blocking.','EXAM TIP: Context switch = pure overhead (no useful work). Goal: minimize frequency.<br><a href="sistemas_operacoes_estudo__2_.html#4-estruturas-de-decisão-e-ciclos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §4 Estruturas de Decisão e Ciclos ↗</a>'],
  ['Processos','184','Can context switching occur during kernel execution?',['No; kernel is protected','Yes; OS can preempt even in kernel if needed','Only with interrupts','Never in modern systems'],1,'Context switch = saving current process state to PCB, loading another process state from PCB, and transferring CPU control. Triggered by timer interrupt or process blocking.','Remember: exec does NOT create new process. Same PID, new program. Pattern: fork() then exec().<br><a href="sistemas_operacoes_estudo__2_.html#4-estruturas-de-decisão-e-ciclos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §4 Estruturas de Decisão e Ciclos ↗</a>'],
  ['Processos','185','What is the relationship between scheduling and context switching?',['Unrelated','Scheduling decisions trigger context switches to change running process','Context switches determine scheduling','They cancel each other'],1,'Context switch = saving current process state to PCB, loading another process state from PCB, and transferring CPU control. Triggered by timer interrupt or process blocking.','EXAM TIP: Context switch = pure overhead (no useful work). Goal: minimize frequency.<br><a href="sistemas_operacoes_estudo__2_.html#4-estruturas-de-decisão-e-ciclos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §4 Estruturas de Decisão e Ciclos ↗</a>'],
  ['Processos','186','What is progress (second requirement)?',['Making forward motion','If no process in CS and some want to enter, one is selected; decision not postponed','All processes entering CS','Fast execution'],1,'The correct answer is \'If no process in CS and some want to enter, one is selected; decision not postponed\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#62-os-3-requisitos-de-uma-solução" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §62 Os 3 Requisitos de uma Solução ↗</a>'],
  ['Processos','187','What does wait() on a semaphore do?',['Waits for time to pass','If semaphore > 0, decrements and continues; else blocks in queue','Always blocks','Signals an event'],1,'wait() blocks parent until any child terminates. Returns terminated child\'s PID. Prevents zombie accumulation. waitpid() can wait for specific child.','Remember: wait() = P() = down(). signal() = V() = up(). P and V from Dutch.<br><a href="sistemas_operacoes_estudo__2_.html#38-terminação-de-processos-exit-wait-zombie-orphan" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §38 Terminação de Processos (exit, wait, zombie, orphan) ↗</a>'],
  ['Processos','188','What is copy-on-write?',['Copying before writing','Pages shared initially; copied only when modified','Write-protecting all pages','Memory duplication'],1,'The correct answer is \'Pages shared initially; copied only when modified\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#29-conceito-de-processo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §29 Conceito de Processo ↗</a>'],
  ['Processos','189','Why is copy-on-write efficient?',['It\'s not efficient','Avoids expensive copying if pages not modified','Reduces write time','Simplifies memory management'],1,'The correct answer is \'Avoids expensive copying if pages not modified\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#21-componentes-principais-de-um-so" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §21 Componentes Principais de um SO ↗</a>'],
  ['Processos','190','What is the difference between wait() and signal()?',['No difference','wait() decrements (may block); signal() increments (may wake)','Both are identical','signal() decrements'],1,'wait() blocks parent until any child terminates. Returns terminated child\'s PID. Prevents zombie accumulation. waitpid() can wait for specific child.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#38-terminação-de-processos-exit-wait-zombie-orphan" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §38 Terminação de Processos (exit, wait, zombie, orphan) ↗</a>'],
  ['Processos','191','Context switching represents:',['Useful computation time','Pure overhead — CPU time spent saving and restoring process state, producing no user work','A scheduling algorithm itself','A form of deadlock between processes'],1,'Context switch: save PCB of current process, restore PCB of next. Takes microseconds during which no user work is done — pure overhead. Minimizing this is one reason time quantum should not be too small.','Smaller quantum → more context switches → more overhead.<br><a href="sistemas_operacoes_estudo__2_.html#4-estruturas-de-decisão-e-ciclos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §4 Estruturas de Decisão e Ciclos ↗</a>'],
  ['IPC','192','What are the two main categories of IPC?',['Local and remote','Shared memory and message passing','Synchronous and asynchronous','Blocking and non-blocking'],1,'The correct answer is \'Shared memory and message passing\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#39-comunicação-entre-processos-ipc" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §39 Comunicação entre Processos (IPC) ↗</a>'],
  ['IPC','193','How does message passing IPC work?',['Processes share memory directly','Processes send/receive messages via explicit send() and receive() calls','Data is copied once at initialization','Messages are broadcast to all processes'],1,'The correct answer is \'Processes send/receive messages via explicit send() and receive() calls\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#39-comunicação-entre-processos-ipc" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §39 Comunicação entre Processos (IPC) ↗</a>'],
  ['IPC','194','What is the main disadvantage of message passing?',['It is complex to implement','Slower than shared memory; requires kernel involvement for each message','It cannot be used locally','It requires hardware support'],1,'The correct answer is \'Slower than shared memory; requires kernel involvement for each message\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#40-modelos-de-ipc-message-passing-vs-shared-memory" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §40 Modelos de IPC: Message Passing vs Shared Memory ↗</a>'],
  ['IPC','195','What happens when reading from an empty pipe?',['The read returns empty data immediately','The reading process blocks until data is available','An error is generated','The pipe closes automatically'],1,'The correct answer is \'The reading process blocks until data is available\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#41-pipes" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §41 Pipes ↗</a>'],
  ['IPC','196','What happens when reading from a pipe with no writers?',['The read blocks forever','The read returns EOF (End of File)','An error is generated','The process terminates'],1,'The correct answer is \'The read returns EOF (End of File)\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#41-pipes" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §41 Pipes ↗</a>'],
  ['IPC','197','What happens when writing to a full pipe?',['The data is discarded','The write blocks until space is available','An error occurs','The pipe shrinks'],1,'The correct answer is \'The write blocks until space is available\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#41-pipes" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §41 Pipes ↗</a>'],
  ['IPC','198','How does the shell implement the pipeline "ls | grep .txt"?',['The shell runs them sequentially','Shell creates ls and grep processes, connects ls\'s stdout to grep\'s stdin via a pipe','Shell does not support this','The shell copies data manually'],1,'The correct answer is \'Shell creates ls and grep processes, connects ls\'s stdout to grep\'s stdin via a pipe\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#41-pipes" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §41 Pipes ↗</a>'],
  ['IPC','199','What is SIGTERM?',['A signal that terminates the system','A signal requesting graceful termination of a process; the process can catch and handle it','A signal that cannot be caught','A signal that restarts the process'],1,'The correct answer is \'A signal requesting graceful termination of a process; the process can catch and handle it\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#41-pipes" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §41 Pipes ↗</a>'],
  ['IPC','200','Why might a process prefer to receive SIGTERM rather than SIGKILL?',['SIGTERM is faster','SIGTERM allows the process to clean up resources and exit gracefully before termination','SIGKILL is better; SIGTERM is unnecessary','No difference between them'],1,'The correct answer is \'SIGTERM allows the process to clean up resources and exit gracefully before termination\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#41-pipes" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §41 Pipes ↗</a>'],
  ['IPC','201','What does IPC stand for?',['Inter-program Computation','Interprocess Communication','Internal Protocol Communication','Internet Process Control'],1,'The correct answer is \'Interprocess Communication\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#39-comunicação-entre-processos-ipc" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §39 Comunicação entre Processos (IPC) ↗</a>'],
  ['IPC','202','Why is IPC necessary in complex systems?',['It is not necessary','Processes need to exchange data and coordinate, and neither shared memory nor message passing works universally','All processes should be independent','IPC slows down systems'],1,'The correct answer is \'Processes need to exchange data and coordinate, and neither shared memory nor message passing works universally\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#39-comunicação-entre-processos-ipc" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §39 Comunicação entre Processos (IPC) ↗</a>'],
  ['IPC','203','What are the two fundamental IPC models?',['Local and remote','Shared memory and message passing','Synchronous and asynchronous','Blocking and non-blocking'],1,'The correct answer is \'Shared memory and message passing\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#39-comunicação-entre-processos-ipc" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §39 Comunicação entre Processos (IPC) ↗</a>'],
  ['IPC','204','What is the speed comparison between shared memory and message passing?',['Both have equal speed','Shared memory is faster; message passing requires kernel involvement','Message passing is faster','Speed depends on the OS'],1,'The correct answer is \'Shared memory is faster; message passing requires kernel involvement\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#40-modelos-de-ipc-message-passing-vs-shared-memory" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §40 Modelos de IPC: Message Passing vs Shared Memory ↗</a>'],
  ['IPC','205','What happens when a process writes to a full pipe?',['The write returns successfully but data is lost','The write blocks until space becomes available','An error is generated','The pipe expands automatically'],1,'The correct answer is \'The write blocks until space becomes available\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#41-pipes" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §41 Pipes ↗</a>'],
  ['IPC','206','What happens when a process reads from an empty pipe?',['The read returns empty data','The reading process blocks until data is available','An error is generated','EOF is returned immediately'],1,'The correct answer is \'The reading process blocks until data is available\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#41-pipes" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §41 Pipes ↗</a>'],
  ['IPC','207','What happens when a process reads from a pipe with all writers closed?',['The read blocks forever','The read returns EOF','An error is generated','The process terminates'],1,'The correct answer is \'The read returns EOF\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#41-pipes" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §41 Pipes ↗</a>'],
  ['IPC','208','What happens when a process writes to a pipe with all readers closed?',['The write succeeds silently','The OS sends SIGPIPE signal; write fails if signal is ignored','An error is generated','The pipe expands automatically'],1,'The correct answer is \'The OS sends SIGPIPE signal; write fails if signal is ignored\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#41-pipes" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §41 Pipes ↗</a>'],
  ['IPC','209','What does the shell symbol "|" do?',['Logical OR','Creates a pipe between two processes: left process\'s stdout to right process\'s stdin','Bitwise AND','File redirection'],1,'The correct answer is \'Creates a pipe between two processes: left process\'s stdout to right process\'s stdin\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#41-pipes" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §41 Pipes ↗</a>'],
  ['IPC','210','In the command "cat file.txt | grep hello | wc -l", how many pipes are created?',['One','Two: one between cat and grep, another between grep and wc','Three','Zero'],1,'The correct answer is \'Two: one between cat and grep, another between grep and wc\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#41-pipes" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §41 Pipes ↗</a>'],
  ['IPC','211','How does the shell set up a pipeline?',['It runs commands sequentially','It creates processes for each command, connects their stdin/stdout with pipes, and waits for all to complete','It cannot set up pipelines','It uses shared memory'],1,'The correct answer is \'It creates processes for each command, connects their stdin/stdout with pipes, and waits for all to complete\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#41-pipes" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §41 Pipes ↗</a>'],
  ['IPC','212','How are named pipes created?',['With the pipe() system call','With the mkfifo() command or system call','Named pipes are created automatically','Via file creation'],1,'The correct answer is \'With the mkfifo() command or system call\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#41-pipes" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §41 Pipes ↗</a>'],
  ['IPC','213','What is shared memory in IPC?',['Memory shared by the kernel and user programs','A region of memory that multiple processes can read and write directly','The computer\'s RAM','A cache system'],1,'The correct answer is \'A region of memory that multiple processes can read and write directly\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#39-comunicação-entre-processos-ipc" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §39 Comunicação entre Processos (IPC) ↗</a>'],
  ['IPC','214','What synchronization primitive is typically used with shared memory?',['Signals','Mutexes, semaphores, or other locks to prevent race conditions','Pipes','No synchronization is needed'],1,'The correct answer is \'Mutexes, semaphores, or other locks to prevent race conditions\' because it accurately describes the concept.','Master concepts: Critical section, mutex, semaphore, deadlock conditions, classic problems.<br><a href="sistemas_operacoes_estudo__2_.html#40-modelos-de-ipc-message-passing-vs-shared-memory" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §40 Modelos de IPC: Message Passing vs Shared Memory ↗</a>'],
  ['IPC','215','What happens if two processes write to the same location in shared memory simultaneously?',['The writes are serialized automatically','A race condition occurs; result depends on timing; both writes or only one may succeed','The OS prevents this automatically','No conflict occurs'],1,'The correct answer is \'A race condition occurs; result depends on timing; both writes or only one may succeed\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#40-modelos-de-ipc-message-passing-vs-shared-memory" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §40 Modelos de IPC: Message Passing vs Shared Memory ↗</a>'],
  ['IPC','216','How can the producer-consumer problem be solved?',['Ignore it','With bounded buffers, synchronization primitives (semaphores, mutexes), and condition variables','It cannot be solved','By eliminating the producer'],1,'Producer-Consumer: producers add to shared buffer, consumers remove. Need synchronization for: (1) mutual exclusion on buffer, (2) empty slots, (3) full slots.','Classic problem: Need 3 semaphores - mutex (access), empty (slots), full (items).<br><a href="sistemas_operacoes_estudo__2_.html#78-problemas-clássicos--bounded-buffer" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §78 Problemas Clássicos — Bounded Buffer ↗</a>'],
  ['IPC','217','Why might a process prefer message passing over shared memory?',['No reason; they are identical','Explicit message passing with implicit synchronization reduces complexity and race condition risk','Shared memory is always better','No such preference exists'],1,'The correct answer is \'Explicit message passing with implicit synchronization reduces complexity and race condition risk\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#40-modelos-de-ipc-message-passing-vs-shared-memory" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §40 Modelos de IPC: Message Passing vs Shared Memory ↗</a>'],
  ['IPC','218','Why might a process prefer shared memory over message passing?',['No reason; they are identical','Shared memory is faster and suitable for high-bandwidth data sharing','Message passing is always better','No preference exists'],1,'The correct answer is \'Shared memory is faster and suitable for high-bandwidth data sharing\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#40-modelos-de-ipc-message-passing-vs-shared-memory" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §40 Modelos de IPC: Message Passing vs Shared Memory ↗</a>'],
  ['IPC','219','What is the locking overhead in shared memory IPC?',['No overhead','The cost of acquiring and releasing locks; can be significant if contentious','Minimal on all systems','Overhead is unpredictable'],1,'The correct answer is \'The cost of acquiring and releasing locks; can be significant if contentious\' because it accurately describes the concept.','Master concepts: Critical section, mutex, semaphore, deadlock conditions, classic problems.<br><a href="sistemas_operacoes_estudo__2_.html#39-comunicação-entre-processos-ipc" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §39 Comunicação entre Processos (IPC) ↗</a>'],
  ['IPC','220','What is the copying overhead in message passing?',['No overhead','Data must be copied from sender to kernel and from kernel to receiver','Minimal on all systems','Overhead is unpredictable'],1,'The correct answer is \'Data must be copied from sender to kernel and from kernel to receiver\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#40-modelos-de-ipc-message-passing-vs-shared-memory" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §40 Modelos de IPC: Message Passing vs Shared Memory ↗</a>'],
  ['IPC','221','Can a single process use multiple IPC mechanisms?',['No; only one can be used','Yes; different mechanisms for different purposes is common','Only in theory','Depends on the OS'],1,'The correct answer is \'Yes; different mechanisms for different purposes is common\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#39-comunicação-entre-processos-ipc" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §39 Comunicação entre Processos (IPC) ↗</a>'],
  ['IPC','222','What is atomic writing to a pipe?',['Breaking the pipe into atoms','Writing up to PIPE_BUF bytes atomically; larger writes may be interleaved with other writes','All writes are atomic','Writes are never atomic'],1,'The correct answer is \'Writing up to PIPE_BUF bytes atomically; larger writes may be interleaved with other writes\' because it accurately describes the concept.','Master concepts: Critical section, mutex, semaphore, deadlock conditions, classic problems.<br><a href="sistemas_operacoes_estudo__2_.html#41-pipes" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §41 Pipes ↗</a>'],
  ['IPC','223','What are the durability characteristics of different IPC mechanisms?',['All are equally durable','Shared memory is volatile; file-backed shared memory and message queues can be persistent','Pipes are persistent','None are durable'],1,'The correct answer is \'Shared memory is volatile; file-backed shared memory and message queues can be persistent\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#39-comunicação-entre-processos-ipc" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §39 Comunicação entre Processos (IPC) ↗</a>'],
  ['IPC','224','Can a process accidentally modify another process\'s memory via IPC?',['No; it is impossible','Yes; if both attach to the same shared memory without proper synchronization, accidental overwrites can happen','Only intentionally','Depends on the CPU'],1,'The correct answer is \'Yes; if both attach to the same shared memory without proper synchronization, accidental overwrites can happen\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#39-comunicação-entre-processos-ipc" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §39 Comunicação entre Processos (IPC) ↗</a>'],
  ['IPC','225','(Another question) - What is data integrity in IPC?',['The data\'s size','Ensuring data is not corrupted during transmission; can be verified with checksums or cryptographic hashes','How the data is stored','Integrity is not applicable to IPC'],1,'The correct answer is \'Ensuring data is not corrupted during transmission; can be verified with checksums or cryptographic hashes\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#39-comunicação-entre-processos-ipc" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §39 Comunicação entre Processos (IPC) ↗</a>'],
  ['IPC','226','What is the bounded buffer producer-consumer problem?',['Buffer that cannot grow','Producer fills buffer; consumer empties it; preventing overflow/underflow','Only one producer allowed','No solution exists'],1,'Producer-Consumer: producers add to shared buffer, consumers remove. Need synchronization for: (1) mutual exclusion on buffer, (2) empty slots, (3) full slots.','Classic problem: Need 3 semaphores - mutex (access), empty (slots), full (items).<br><a href="sistemas_operacoes_estudo__2_.html#78-problemas-clássicos--bounded-buffer" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §78 Problemas Clássicos — Bounded Buffer ↗</a>'],
  ['Escalonamento','227','In the context of OS goals, what does "throughput" measure?',['The size of files processed','The amount of data transferred per second','The number of processes completed per unit time','The latency of a single operation'],2,'Throughput = number of processes completed per unit time. Higher is better. SJF maximizes throughput for given set of processes.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#17-o-que-é-um-sistema-operativo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §17 O que é um Sistema Operativo? ↗</a>'],
  ['Escalonamento','228','What is the difference between preemptive and non-preemptive scheduling?',['They are the same','Preemptive: OS can interrupt running process; Non-preemptive: process must voluntarily yield','Preemptive is older','No practical difference'],1,'Preemptive: OS can forcibly take CPU (timer interrupt). Non-preemptive: process runs until it voluntarily yields or blocks. Preemptive allows better response time.','Study all algorithms: FCFS, SJF, SRTF, RR, Priority, MLFQ. Know metrics: waiting, turnaround, response.<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','229','What are CPU-bound processes?',['Processes that use no CPU','Processes that perform mostly computation with few I/O requests','Processes that are stuck in loops','Processes that cannot use multiple CPUs'],1,'The correct answer is \'Processes that perform mostly computation with few I/O requests\' because it accurately describes the concept.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#43-ciclo-cpu-io-burst" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §43 Ciclo CPU-I/O Burst ↗</a>'],
  ['Escalonamento','230','What is FCFS scheduling?',['Fast CPU First Serve','First-Come First-Served: processes run in arrival order, non-preemptive','File Cache First Schedule','Failure Check For Service'],1,'FCFS (First-Come First-Served) schedules processes in arrival order. Simple, non-preemptive, but suffers from convoy effect when short processes wait behind long ones.','Remember: FCFS = simple queue, non-preemptive. Convoy effect: short jobs stuck behind long. No starvation.<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','231','What is the main advantage of FCFS?',['Optimal response time','Simple to implement and understand','Best throughput','Prevents starvation'],1,'FCFS (First-Come First-Served) schedules processes in arrival order. Simple, non-preemptive, but suffers from convoy effect when short processes wait behind long ones.','Remember: FCFS = simple queue, non-preemptive. Convoy effect: short jobs stuck behind long. No starvation.<br><a href="sistemas_operacoes_estudo__2_.html#46-first-come-first-served-fcfs" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §46 First-Come First-Served (FCFS) ↗</a>'],
  ['Escalonamento','232','What is the main disadvantage of FCFS?',['Complex to implement','Poor response time and convoy effect; inflexible','Uses too much memory','Requires preemption'],1,'FCFS (First-Come First-Served) schedules processes in arrival order. Simple, non-preemptive, but suffers from convoy effect when short processes wait behind long ones.','Remember: FCFS = simple queue, non-preemptive. Convoy effect: short jobs stuck behind long. No starvation.<br><a href="sistemas_operacoes_estudo__2_.html#46-first-come-first-served-fcfs" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §46 First-Come First-Served (FCFS) ↗</a>'],
  ['Escalonamento','233','What is Round Robin (RR) scheduling?',['Processes arranged in a circle','FCFS with time quantum; each process gets CPU for fixed time then preempted','Rotating CPU access','Random selection of processes'],1,'Round Robin allocates fixed time slices (quantum) to each process in circular order. Provides fairness and good response time but has context switch overhead. Quantum too small → overhead; too large → becomes FCFS.','Remember: RR quantum rule - too small (< 1ms) → overhead. Too large (> 100ms) → becomes FCFS. Typical: 10-100ms.<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','234','What happens when a process uses less than its time quantum in RR?',['It continues running until quantum expires','It voluntarily yields to the next process (e.g., on I/O request)','It gets more CPU time','It is terminated'],1,'Round Robin allocates fixed time slices (quantum) to each process in circular order. Provides fairness and good response time but has context switch overhead. Quantum too small → overhead; too large → becomes FCFS.','Study all algorithms: FCFS, SJF, SRTF, RR, Priority, MLFQ. Know metrics: waiting, turnaround, response.<br><a href="sistemas_operacoes_estudo__2_.html#47-round-robin-rr" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §47 Round Robin (RR) ↗</a>'],
  ['Escalonamento','235','What is Shortest Job First (SJF)?',['The shortest program runs first','Process with shortest expected CPU burst runs next, non-preemptive','Fastest process selected','Process with least memory needs'],1,'SJF (Shortest Job First) is provably optimal for minimizing average waiting time. Non-preemptive. Challenge: predicting burst time. Can starve long processes.','Exam tip: SJF is OPTIMAL for avg waiting time. But: needs burst prediction + can starve long jobs.<br><a href="sistemas_operacoes_estudo__2_.html#48-shortest-job-first-sjf-e-previsão-do-próximo-burst" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §48 Shortest-Job-First (SJF) e Previsão do Próximo Burst ↗</a>'],
  ['Escalonamento','236','What is the main advantage of SJF?',['Easy to implement','Provably optimal average waiting time among non-preemptive algorithms','Prevents starvation','Works with I/O-bound processes'],1,'SJF (Shortest Job First) is provably optimal for minimizing average waiting time. Non-preemptive. Challenge: predicting burst time. Can starve long processes.','Exam tip: SJF is OPTIMAL for avg waiting time. But: needs burst prediction + can starve long jobs.<br><a href="sistemas_operacoes_estudo__2_.html#48-shortest-job-first-sjf-e-previsão-do-próximo-burst" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §48 Shortest-Job-First (SJF) e Previsão do Próximo Burst ↗</a>'],
  ['Escalonamento','237','What is the main disadvantage of SJF?',['Complex implementation','Future burst length is unknown; long processes may starve','Requires preemption','Cannot handle multiple CPUs'],1,'SJF (Shortest Job First) is provably optimal for minimizing average waiting time. Non-preemptive. Challenge: predicting burst time. Can starve long processes.','Exam tip: SJF is OPTIMAL for avg waiting time. But: needs burst prediction + can starve long jobs.<br><a href="sistemas_operacoes_estudo__2_.html#48-shortest-job-first-sjf-e-previsão-do-próximo-burst" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §48 Shortest-Job-First (SJF) e Previsão do Próximo Burst ↗</a>'],
  ['Escalonamento','238','How does the OS estimate future CPU burst in SJF?',['It asks the user','Using exponential averaging of past bursts','Randomly guessing','It cannot estimate'],1,'SJF (Shortest Job First) is provably optimal for minimizing average waiting time. Non-preemptive. Challenge: predicting burst time. Can starve long processes.','Exam tip: SJF is OPTIMAL for avg waiting time. But: needs burst prediction + can starve long jobs.<br><a href="sistemas_operacoes_estudo__2_.html#43-ciclo-cpu-io-burst" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §43 Ciclo CPU-I/O Burst ↗</a>'],
  ['Escalonamento','239','What is Shortest Remaining Time First (SRTF)?',['The shortest total remaining time','Preemptive SJF: always runs process with shortest remaining time','Process with least remaining I/O','Fastest remaining process'],1,'SRTF (Shortest Remaining Time First) is preemptive SJF. Switches to shorter job when it arrives. Optimal for minimizing average waiting time but causes more context switches.','Tip: SRTF = preemptive SJF. More context switches but better performance. Still optimal for avg waiting time.<br><a href="sistemas_operacoes_estudo__2_.html#49-shortest-remaining-time-first-srtf" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §49 Shortest-Remaining-Time-First (SRTF) ↗</a>'],
  ['Escalonamento','240','What is the main advantage of SRTF?',['Simple to implement','Optimal average waiting time among preemptive algorithms','Prevents long process starvation','No context switches'],1,'SRTF (Shortest Remaining Time First) is preemptive SJF. Switches to shorter job when it arrives. Optimal for minimizing average waiting time but causes more context switches.','Tip: SRTF = preemptive SJF. More context switches but better performance. Still optimal for avg waiting time.<br><a href="sistemas_operacoes_estudo__2_.html#49-shortest-remaining-time-first-srtf" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §49 Shortest-Remaining-Time-First (SRTF) ↗</a>'],
  ['Escalonamento','241','What is the main disadvantage of SRTF?',['Complex','Long jobs may starve due to continuous preemption by shorter jobs','Cannot estimate burst times','Requires more memory'],1,'SRTF (Shortest Remaining Time First) is preemptive SJF. Switches to shorter job when it arrives. Optimal for minimizing average waiting time but causes more context switches.','Tip: SRTF = preemptive SJF. More context switches but better performance. Still optimal for avg waiting time.<br><a href="sistemas_operacoes_estudo__2_.html#49-shortest-remaining-time-first-srtf" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §49 Shortest-Remaining-Time-First (SRTF) ↗</a>'],
  ['Escalonamento','242','What is Priority Scheduling?',['Scheduling based on user preferences','Always running the highest-priority ready process','Scheduling important files first','Prioritizing I/O requests'],1,'Priority Scheduling runs highest priority process first. Can be preemptive or non-preemptive. Problem: starvation of low-priority processes. Solution: aging.','Study all algorithms: FCFS, SJF, SRTF, RR, Priority, MLFQ. Know metrics: waiting, turnaround, response.<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','243','How is starvation solved in priority scheduling?',['By eliminating priorities','Using aging: gradually increase priority of waiting processes','By running processes slower','Starvation cannot be solved'],1,'Aging prevents starvation in priority scheduling by gradually increasing the priority of waiting processes over time.','Study all algorithms: FCFS, SJF, SRTF, RR, Priority, MLFQ. Know metrics: waiting, turnaround, response.<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','244','What are priority levels in Linux?',['0-5','-20 to +19 (nice values); -20 is highest priority','0-100','1-10'],1,'Priority Scheduling runs highest priority process first. Can be preemptive or non-preemptive. Problem: starvation of low-priority processes. Solution: aging.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#50-priority-scheduling" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §50 Priority Scheduling ↗</a>'],
  ['Escalonamento','245','What does a lower nice value mean?',['Lower priority','Higher priority (more CPU time)','Same priority','Nice value has no effect'],1,'The correct answer is \'Higher priority (more CPU time)\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#50-priority-scheduling" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §50 Priority Scheduling ↗</a>'],
  ['Escalonamento','246','What is the main advantage of MLQ?',['Prevents all starvation','Low overhead; clear separation of process types','Simple implementation','Optimal response time'],1,'The correct answer is \'Low overhead; clear separation of process types\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#51-multilevel-queue-mlq" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §51 Multilevel Queue (MLQ) ↗</a>'],
  ['Escalonamento','247','What is the main disadvantage of MLQ?',['Complex implementation','Inflexible: process assigned permanently to queue; cannot move if behavior changes','Cannot handle interactive processes','Requires user classification'],1,'The correct answer is \'Inflexible: process assigned permanently to queue; cannot move if behavior changes\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#51-multilevel-queue-mlq" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §51 Multilevel Queue (MLQ) ↗</a>'],
  ['Escalonamento','248','How does MLFQ decide process demotion?',['Randomly','If process uses full time quantum without completing, move to lower-priority queue','Based on memory usage','Never demote'],1,'MLFQ uses multiple queues with different priorities. Processes move between queues based on behavior. Long CPU bursts → demoted; short bursts → promoted. Prevents starvation while favoring interactive processes.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#52-multilevel-feedback-queue-mlfq" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §52 Multilevel Feedback Queue (MLFQ) ↗</a>'],
  ['Escalonamento','249','How does MLFQ decide process promotion?',['Based on I/O patterns','Configurable: after time in queue or if process becomes interactive','Never promote','Based on user request'],1,'MLFQ uses multiple queues with different priorities. Processes move between queues based on behavior. Long CPU bursts → demoted; short bursts → promoted. Prevents starvation while favoring interactive processes.','Process states, PCB, fork/exec/wait/exit, zombies, orphans, context switch.<br><a href="sistemas_operacoes_estudo__2_.html#52-multilevel-feedback-queue-mlfq" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §52 Multilevel Feedback Queue (MLFQ) ↗</a>'],
  ['Escalonamento','250','What is the main advantage of MLFQ?',['Guaranteed no starvation','Adaptive: approximates SRTF without knowing future burst lengths','Simple parameter tuning','Prevents all preemption'],1,'MLFQ uses multiple queues with different priorities. Processes move between queues based on behavior. Long CPU bursts → demoted; short bursts → promoted. Prevents starvation while favoring interactive processes.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#52-multilevel-feedback-queue-mlfq" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §52 Multilevel Feedback Queue (MLFQ) ↗</a>'],
  ['Escalonamento','251','What is the main disadvantage of MLFQ?',['Inflexible','Complex tuning of 5 parameters; can be unpredictable','Not preemptive','Cannot handle I/O'],1,'MLFQ uses multiple queues with different priorities. Processes move between queues based on behavior. Long CPU bursts → demoted; short bursts → promoted. Prevents starvation while favoring interactive processes.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#52-multilevel-feedback-queue-mlfq" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §52 Multilevel Feedback Queue (MLFQ) ↗</a>'],
  ['Escalonamento','252','What is virtual runtime (vruntime) in CFS?',['Time that doesn\'t exist','CPU time weighted by nice value; process with lowest vruntime selected','Time spent in queue','Wall-clock time'],1,'The correct answer is \'CPU time weighted by nice value; process with lowest vruntime selected\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#53-completely-fair-scheduler-cfs--linux" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §53 Completely Fair Scheduler (CFS) — Linux ↗</a>'],
  ['Escalonamento','253','How does nice value affect vruntime in CFS?',['No effect','Higher priority (lower nice) causes vruntime to grow slower','Lower nice values increase vruntime faster','Nice value only affects process name'],1,'The correct answer is \'Higher priority (lower nice) causes vruntime to grow slower\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#50-priority-scheduling" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §50 Priority Scheduling ↗</a>'],
  ['Escalonamento','254','What is priority inversion?',['Reversing process priorities','Lower-priority process blocking higher-priority process (e.g., holding a lock)','High priority becoming low','Process reordering'],1,'Priority Scheduling runs highest priority process first. Can be preemptive or non-preemptive. Problem: starvation of low-priority processes. Solution: aging.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','255','How can priority inversion be prevented?',['By not using priorities','Using priority inheritance or priority ceiling protocols','By ignoring it','Starvation always occurs'],1,'Priority Scheduling runs highest priority process first. Can be preemptive or non-preemptive. Problem: starvation of low-priority processes. Solution: aging.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','256','What is Rate Monotonic (RM) scheduling?',['Scheduling based on rates','Real-time algorithm: highest priority to task with shortest period','Scheduling related to monotonic functions','Process rate control'],1,'The correct answer is \'Real-time algorithm: highest priority to task with shortest period\' because it accurately describes the concept.','Study all algorithms: FCFS, SJF, SRTF, RR, Priority, MLFQ. Know metrics: waiting, turnaround, response.<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','257','What is Earliest Deadline First (EDF) scheduling?',['Scheduling based on process names','Real-time algorithm: highest priority to task with nearest deadline','First-come scheduling','Task elimination'],1,'The correct answer is \'Real-time algorithm: highest priority to task with nearest deadline\' because it accurately describes the concept.','Study all algorithms: FCFS, SJF, SRTF, RR, Priority, MLFQ. Know metrics: waiting, turnaround, response.<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','258','What is turnaround time?',['Time to turn around','Time from process submission to completion','Context switch time','I/O wait time'],1,'Turnaround time = completion time - arrival time. Total time from arrival to completion. Includes waiting time + burst time.','Formula: Turnaround = Completion - Arrival = Waiting + Burst. Minimize for better user experience.<br><a href="sistemas_operacoes_estudo__2_.html#45-critérios-de-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §45 Critérios de Escalonamento ↗</a>'],
  ['Escalonamento','259','What is response time?',['Time to respond to input','Time from request to first response (not completion)','Execution time','Total CPU time'],1,'Response time = time from arrival to first CPU execution. Critical for interactive systems. RR provides good response time.','Formula: Response = First_Run - Arrival. RR gives best response time for interactive systems.<br><a href="sistemas_operacoes_estudo__2_.html#45-critérios-de-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §45 Critérios de Escalonamento ↗</a>'],
  ['Escalonamento','260','Can starvation resolve itself?',['No; permanent','Yes; if high-priority work stops or aging increases priority','Never resolves','Only with reboot'],1,'The correct answer is \'Yes; if high-priority work stops or aging increases priority\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#24-arranque-do-computador-boot" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §24 Arranque do Computador (Boot) ↗</a>'],
  ['Escalonamento','261','Which scheduling criterion measures total time from process submission to completion?',['Waiting time','Response time','Turnaround time','Burst time'],2,'Turnaround time = completion time − arrival time. It includes waiting + execution + I/O time.','Turnaround = waiting time + burst time (in simple cases without I/O).<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','262','FCFS (First-Come First-Served) scheduling is:',['Preemptive','Non-preemptive','Both preemptive and non-preemptive','Neither preemptive nor a scheduler'],1,'FCFS is non-preemptive — once a process gets CPU, it runs until it finishes or blocks voluntarily.','FCFS suffers from the convoy effect: short jobs stuck waiting behind long ones.<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','263','The convoy effect is associated with which scheduling algorithm?',['SJF','Round Robin','FCFS','Priority Scheduling'],2,'FCFS convoy effect: one long process holds CPU while many short processes wait, reducing overall CPU and device utilization.','Analogy: one slow truck blocking a line of fast cars.<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','264','SJF (Shortest Job First) is optimal because:',['It is the simplest algorithm','It gives minimum average waiting time for any given set of processes','It is always preemptive','It requires no knowledge of burst time'],1,'SJF minimizes average waiting time — provably optimal. Moving a short job before a long one always reduces total wait.','SJF is priority scheduling where priority = 1/burst_time.<br><a href="sistemas_operacoes_estudo__2_.html#48-shortest-job-first-sjf-e-previsão-do-próximo-burst" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §48 Shortest-Job-First (SJF) e Previsão do Próximo Burst ↗</a>'],
  ['Escalonamento','265','The main practical problem with SJF scheduling is:',['It causes starvation of all processes','CPU burst length cannot be known in advance — only estimated','It only works on single-core CPUs','It requires mandatory preemption'],1,'SJF requires knowing future CPU burst lengths, which is impossible. We estimate using exponential averaging of past bursts.','Estimate: τ_{n+1} = α·t_n + (1−α)·τ_n. Typically α = 0.5.<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','266','Preemptive SJF is also known as:',['Priority Scheduling','Shortest Remaining Time First (SRTF)','Round Robin','Multilevel Queue'],1,'Preemptive SJF = SRTF: if a new process arrives with burst shorter than remaining time of current process, preempt the current process.','SRTF gives optimal average waiting time among all preemptive algorithms.<br><a href="sistemas_operacoes_estudo__2_.html#44-decisões-de-escalonamento--preemptivo-vs-não-preemptivo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §44 Decisões de Escalonamento — Preemptivo vs Não-Preemptivo ↗</a>'],
  ['Escalonamento','267','In Round Robin scheduling, what happens when a process\'s time quantum expires?',['It terminates','It is preempted and placed at the back of the ready queue','It gets a priority boost','It moves to a lower-priority queue'],1,'When quantum expires, timer interrupt fires, OS preempts current process, places it at the tail of the ready queue, and schedules the next process from the head.','Every ready process gets CPU within (n−1)×q time units maximum.<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','268','If the time quantum in Round Robin is set very large, it behaves like:',['SJF','SRTF','FCFS','Priority Scheduling'],2,'With an infinite quantum each process runs to completion before the next starts — exactly FCFS behavior.','Round Robin with q→∞ degenerates to FCFS.<br><a href="sistemas_operacoes_estudo__2_.html#47-round-robin-rr" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §47 Round Robin (RR) ↗</a>'],
  ['Escalonamento','269','What does "starvation" mean in the context of CPU scheduling?',['A process consuming too much CPU','A process waiting indefinitely because higher-priority processes always preempt it','A deadlocked process','A process that terminates prematurely'],1,'Starvation: a process is perpetually denied CPU time because the ready queue always contains higher-priority processes. Common in priority and SJF scheduling.','Solution: aging — gradually increase priority of waiting processes over time.<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','270','Aging is a technique used to solve:',['Deadlock','Starvation','The convoy effect','Context switch overhead'],1,'Aging: as a process waits longer, its priority gradually increases, ensuring it eventually gets CPU time even if initially low priority.','Aging = anti-starvation technique for priority-based scheduling.<br><a href="sistemas_operacoes_estudo__2_.html#50-priority-scheduling" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §50 Priority Scheduling ↗</a>'],
  ['Escalonamento','271','Multilevel Queue scheduling:',['Moves processes between queues freely','Assigns each process permanently to a queue based on process type','Uses only a single queue for all processes','Is always non-preemptive'],1,'Multilevel Queue permanently assigns processes (e.g., foreground vs background). Each queue has its own scheduling algorithm. No movement between queues.','Contrast with Multilevel Feedback Queue which allows movement between queues.<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','272','How does Multilevel Feedback Queue (MLFQ) differ from Multilevel Queue?',['It uses fewer queues','Processes can move between queues based on their CPU behavior','It is always non-preemptive','It uses only FCFS'],1,'MLFQ allows processes to move between queues. CPU-bound processes drop to lower queues over time; I/O-bound/interactive processes stay or rise. Adapts dynamically to behavior.','MLFQ is the most general and widely-used scheduling framework (basis of Unix/Linux schedulers).<br><a href="sistemas_operacoes_estudo__2_.html#51-multilevel-queue-mlq" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §51 Multilevel Queue (MLQ) ↗</a>'],
  ['Escalonamento','273','In MLFQ, a process that always uses its full time quantum will:',['Stay in the highest priority queue','Be moved to lower priority queues over time','Be immediately terminated','Be moved to higher priority queues'],1,'MLFQ penalizes CPU-hungry processes by moving them to lower-priority queues. Processes that release CPU early (I/O-bound) are rewarded by remaining at high priority.','This adaptively identifies and rewards I/O-bound/interactive processes.<br><a href="sistemas_operacoes_estudo__2_.html#47-round-robin-rr" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §47 Round Robin (RR) ↗</a>'],
  ['Escalonamento','274','Response time is most critical for which type of process?',['Batch jobs','Interactive/real-time processes','Background daemons','CPU-bound batch processes'],1,'Interactive processes need fast response to user input. Response time = time from request submission to first response produced.','Round Robin bounds response time to at most (n−1)×q — ideal for time-sharing.<br><a href="sistemas_operacoes_estudo__2_.html#45-critérios-de-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §45 Critérios de Escalonamento ↗</a>'],
  ['Escalonamento','275','Which algorithm gives the best response time for interactive users?',['FCFS','SJF','Round Robin','Non-preemptive priority scheduling'],2,'Round Robin ensures each process gets CPU within one full cycle, bounding maximum response time. Ideal for time-sharing and interactive systems.','Response time with RR ≤ (n−1) × q where n = number of processes, q = time quantum.<br><a href="sistemas_operacoes_estudo__2_.html#45-critérios-de-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §45 Critérios de Escalonamento ↗</a>'],
  ['Escalonamento','276','Throughput in CPU scheduling refers to:',['CPU idle time percentage','Number of processes completing per unit time','Average waiting time of all processes','Time from arrival to completion'],1,'Throughput = processes completed per time unit. Maximized by minimizing overhead (context switches) and efficiently utilizing CPU. SJF tends to maximize throughput.','SJF/SRTF maximizes throughput by finishing short jobs quickly.<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','277','In most OS textbooks, a lower priority number means:',['Lower priority','Higher priority','No priority assigned','Equal priority to all others'],1,'Convention: lower priority number = higher priority (priority 0 runs before priority 10). This varies — always check the convention used in your system.','Linux nice values: −20 (highest priority) to +19 (lowest priority).<br><a href="sistemas_operacoes_estudo__2_.html#50-priority-scheduling" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §50 Priority Scheduling ↗</a>'],
  ['Escalonamento','278','What defines a preemptive scheduling algorithm?',['It runs each process to completion before switching','It can interrupt a running process and give CPU to another','It never performs context switches','It is only used in batch processing systems'],1,'Preemptive: OS can forcibly take CPU from a running process (via timer interrupt or higher-priority arrival). Non-preemptive: process keeps CPU until it voluntarily yields or terminates.','Most modern OSes use preemptive scheduling for responsiveness and fairness.<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','279','Rate Monotonic scheduling assigns priority based on:',['CPU burst time','Process arrival order','Process period — shorter period = higher fixed priority','Random assignment'],2,'Rate Monotonic: shorter period = higher fixed priority. Provably optimal among fixed-priority preemptive algorithms. Schedulable if total CPU utilization ≤ n(2^(1/n)−1).','RM utilization bound approaches ln(2) ≈ 69.3% as number of tasks n→∞.<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','280','Earliest Deadline First (EDF) scheduling works by:',['Assigning fixed priorities at process creation','Always scheduling the process with the earliest absolute deadline','Using FCFS as a tiebreaker','Requiring all processes to declare burst lengths'],1,'EDF: dynamic priority — whichever process has the nearest deadline gets CPU. Can theoretically achieve 100% CPU utilization. Used in both soft and hard real-time systems.','EDF is optimal: no other algorithm can schedule a feasible task set that EDF cannot.<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','281','The Linux Completely Fair Scheduler (CFS) is based on:',['Fixed time slices for all processes','Virtual runtime — always run the process with the smallest accumulated virtual runtime','Static priority levels only','FCFS within priority bands'],1,'CFS tracks virtual_runtime for each process. The process with the smallest virtual_runtime is scheduled next. Lower-weight processes accrue virtual_runtime faster, so higher-weight processes run more.','CFS uses a red-black tree ordered by virtual_runtime for O(log n) scheduling decisions.<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','282','Round Robin performs poorly compared to SJF when:',['All processes have equal burst lengths','Processes have widely varying burst times — long jobs inflate average waiting time','All processes arrive at the same time','There is only a single process'],1,'With varied bursts, RR makes short jobs wait through slices of long jobs. SJF always runs the shortest first, minimizing average wait. RR optimizes response time fairness, not average wait.','RR: fair and bounded response time. SJF: minimal average wait. Different goals.<br><a href="sistemas_operacoes_estudo__2_.html#47-round-robin-rr" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §47 Round Robin (RR) ↗</a>'],
  ['Escalonamento','283','Which scheduling policy is most fair in terms of equal CPU time distribution?',['FCFS','SJF','Round Robin with a small quantum','Non-preemptive priority scheduling'],2,'RR with small quantum gives each process equal CPU shares in turn. Over time all processes receive approximately equal CPU time regardless of burst length.','Fairness and efficiency are often at odds: RR is fair but does not minimize average wait.<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','284','Which of the following is NOT a standard CPU scheduling criterion?',['CPU utilization','Cache line size','Throughput','Waiting time'],1,'Cache line size is a hardware characteristic, not a scheduling performance metric. The five classic criteria are: CPU utilization, throughput, turnaround time, waiting time, response time.','Know the 5 classic scheduling criteria for exams.<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','285','Hardware timer interrupts are essential for preemptive scheduling because:',['They speed up context switching','They allow the OS to forcibly reclaim CPU from a running process at fixed time intervals','They are required for non-preemptive scheduling too','They directly run the scheduler code'],1,'Preemptive scheduling depends on periodic timer interrupts. When the timer fires, control transfers to the OS interrupt handler, which can then perform a context switch to another process.','Without hardware timer: OS cannot preempt — only cooperative/voluntary multitasking is possible.<br><a href="sistemas_operacoes_estudo__2_.html#25-interrupções" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §25 Interrupções ↗</a>'],
  ['Escalonamento','286','Why do schedulers often give I/O-bound processes priority over CPU-bound ones?',['They require more memory','Scheduling them quickly gets their I/O started sooner, overlapping CPU and I/O work to improve throughput','They have higher static priority by default','They never actually need the CPU'],1,'I/O-bound processes issue I/O requests quickly after getting CPU. Prioritizing them starts their I/O early, so CPU and I/O devices can work in parallel — improving total system throughput.','This is why MLFQ rewards processes that release CPU early (likely I/O-bound).<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','287','The scheduling criterion "response time" specifically means:',['Total time from arrival to completion','Time the process spends in the ready queue waiting','Time from request submission to the first response being produced','Number of context switches experienced'],2,'Response time: from when a request is submitted to when the first response is produced. Critical for interactive systems. Different from turnaround (which includes full completion).','Round Robin minimizes worst-case response time; SJF minimizes average waiting/turnaround time.<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Escalonamento','288','In a system using priority scheduling, what problem arises without aging?',['Deadlock between processes','High-priority processes can starve low-priority ones indefinitely','Context switch overhead increases','Round Robin stops working'],1,'Without aging, low-priority processes may never run if high-priority processes continuously arrive. Aging solves this by gradually raising the priority of waiting processes.','Priority scheduling without aging can indefinitely starve low-priority processes.<br><a href="sistemas_operacoes_estudo__2_.html#42-motivação-para-o-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §42 Motivação para o Escalonamento ↗</a>'],
  ['Sincronização','289','Why is mutual exclusion critical in shared resource access?',['It eliminates the need for synchronization','It ensures only one process accesses a critical section at a time','It makes all programs run faster','It removes the need for locks'],1,'The correct answer is \'It ensures only one process accesses a critical section at a time\' because it accurately describes the concept.','Master concepts: Critical section, mutex, semaphore, deadlock conditions, classic problems.<br><a href="sistemas_operacoes_estudo__2_.html#62-os-3-requisitos-de-uma-solução" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §62 Os 3 Requisitos de uma Solução ↗</a>'],
  ['Sincronização','290','How does the OS ensure mutual exclusion for shared kernel data structures?',['It doesn\'t; data corruption is acceptable','It disables interrupts during critical sections or uses atomic instructions','By making all data read-only','Mutual exclusion is not needed'],1,'The correct answer is \'It disables interrupts during critical sections or uses atomic instructions\' because it accurately describes the concept.','Master concepts: Critical section, mutex, semaphore, deadlock conditions, classic problems.<br><a href="sistemas_operacoes_estudo__2_.html#10-estruturas-struct-e-typedefs" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §10 Estruturas (struct) e Typedefs ↗</a>'],
  ['Sincronização','291','How can the readers-writers problem be solved?',['Give all readers priority','Use locks (typically a read-write lock) allowing concurrent readers but exclusive writer access','It cannot be solved','Serialize all accesses'],1,'Readers-Writers: multiple readers OR one writer can access data. Challenge: balance fairness - prevent writer starvation vs reader starvation.','Tradeoff: Favor readers → writer starvation. Favor writers → reader starvation. Need balance.<br><a href="sistemas_operacoes_estudo__2_.html#79-problemas-clássicos--readers-and-writers" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §79 Problemas Clássicos — Readers and Writers ↗</a>'],
  ['Sincronização','292','What is a race condition?',['Processes racing to complete','Outcome depends on timing of concurrent accesses to shared data; non-deterministic','Processes running concurrently','CPU racing against clock'],1,'Race condition occurs when multiple processes access shared data concurrently and result depends on execution order. Leads to inconsistent state. Solution: mutual exclusion.','Remember: Race = outcome depends on execution order. Fix with synchronization (locks, semaphores).<br><a href="sistemas_operacoes_estudo__2_.html#55-critical-sections-e-race-conditions" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §55 Critical Sections e Race Conditions ↗</a>'],
  ['Sincronização','293','Why are race conditions dangerous?',['Mild performance impact','Results are unpredictable and hard to reproduce; causes data corruption','No danger; races are normal','Only affect slow systems'],1,'Race condition occurs when multiple processes access shared data concurrently and result depends on execution order. Leads to inconsistent state. Solution: mutual exclusion.','Remember: Race = outcome depends on execution order. Fix with synchronization (locks, semaphores).<br><a href="sistemas_operacoes_estudo__2_.html#55-critical-sections-e-race-conditions" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §55 Critical Sections e Race Conditions ↗</a>'],
  ['Sincronização','294','What is a critical section?',['A critical part of the program','Code region accessing shared data; only one process should execute it at a time','Part of the kernel','Priority level'],1,'Critical section = code accessing shared resources. Must ensure only one process executes it at a time. Use locks, semaphores, or atomic operations.','3 requirements: Mutual Exclusion, Progress, Bounded Waiting. Miss any → incorrect solution.<br><a href="sistemas_operacoes_estudo__2_.html#55-critical-sections-e-race-conditions" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §55 Critical Sections e Race Conditions ↗</a>'],
  ['Sincronização','295','What three requirements must a critical section solution satisfy?',['Fast, simple, complete','Mutual exclusion, progress, bounded waiting','Security, privacy, efficiency','Atomicity, isolation, consistency'],1,'Critical section requirements: (1) Mutual Exclusion - only one process at a time, (2) Progress - decision can\'t postpone indefinitely, (3) Bounded Waiting - limit on times others enter before you.','3 requirements: Mutual Exclusion, Progress, Bounded Waiting. Miss any → incorrect solution.<br><a href="sistemas_operacoes_estudo__2_.html#55-critical-sections-e-race-conditions" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §55 Critical Sections e Race Conditions ↗</a>'],
  ['Sincronização','296','What is mutual exclusion?',['Excluding mutual processes','Only one process in critical section at a time','Preventing exclusion','Mutual sharing'],1,'The correct answer is \'Only one process in critical section at a time\' because it accurately describes the concept.','Master concepts: Critical section, mutex, semaphore, deadlock conditions, classic problems.<br><a href="sistemas_operacoes_estudo__2_.html#62-os-3-requisitos-de-uma-solução" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §62 Os 3 Requisitos de uma Solução ↗</a>'],
  ['Sincronização','297','What is the "Too Much Milk" problem?',['Having excessive milk','Classic race condition example: roommates both buying milk due to lack of synchronization','Overflow in milk container','Dairy management'],1,'The correct answer is \'Classic race condition example: roommates both buying milk due to lack of synchronization\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#57-o-problema-too-much-milk" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §57 O Problema &quot;Too Much Milk&quot; ↗</a>'],
  ['Sincronização','298','What is Peterson\'s Algorithm?',['Algorithm developed by Peterson','Software-only 2-process critical section solution using flags and turn variable','Process scheduling algorithm','Memory allocation method'],1,'Peterson\'s Algorithm: software-only 2-process mutual exclusion. Uses flag[2] (want to enter) and turn (whose turn). Works without hardware support.','Exam tip: Peterson needs 2 variables: flag[i] (want to enter) + turn (whose turn). Software-only!<br><a href="sistemas_operacoes_estudo__2_.html#64-solução-de-peterson" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §64 Solução de Peterson ↗</a>'],
  ['Sincronização','299','How does Peterson\'s Algorithm work?',['By random selection','Using flag[i] to signal intent and turn to yield priority; busy-waits','Using kernel locks','Using interrupts'],1,'Peterson\'s Algorithm: software-only 2-process mutual exclusion. Uses flag[2] (want to enter) and turn (whose turn). Works without hardware support.','Exam tip: Peterson needs 2 variables: flag[i] (want to enter) + turn (whose turn). Software-only!<br><a href="sistemas_operacoes_estudo__2_.html#64-solução-de-peterson" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §64 Solução de Peterson ↗</a>'],
  ['Sincronização','300','Does Peterson\'s Algorithm satisfy mutual exclusion?',['No; race condition can occur','Yes; turn variable ensures only one can proceed','Sometimes; depends on timing','Only on single CPU'],1,'Peterson\'s Algorithm: software-only 2-process mutual exclusion. Uses flag[2] (want to enter) and turn (whose turn). Works without hardware support.','Exam tip: Peterson needs 2 variables: flag[i] (want to enter) + turn (whose turn). Software-only!<br><a href="sistemas_operacoes_estudo__2_.html#62-os-3-requisitos-de-uma-solução" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §62 Os 3 Requisitos de uma Solução ↗</a>'],
  ['Sincronização','301','What is a spinlock?',['A lock that spins','Process busy-waits checking lock variable until free','A fast lock','Hardware lock'],1,'Spinlock busy-waits in a loop checking lock. Wastes CPU but useful for short critical sections on multiprocessors. No context switch overhead.','Tip: Spinlock = busy wait. Good for multiprocessors + short critical sections. Else wastes CPU.<br><a href="sistemas_operacoes_estudo__2_.html#70-busy-waiting-e-spinlocks" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §70 Busy Waiting e Spinlocks ↗</a>'],
  ['Sincronização','302','When is spinlock appropriate?',['Always','Short critical sections on multiprocessors; waiting is brief','Never; always inefficient','Only for single CPU'],1,'Spinlock busy-waits in a loop checking lock. Wastes CPU but useful for short critical sections on multiprocessors. No context switch overhead.','Tip: Spinlock = busy wait. Good for multiprocessors + short critical sections. Else wastes CPU.<br><a href="sistemas_operacoes_estudo__2_.html#70-busy-waiting-e-spinlocks" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §70 Busy Waiting e Spinlocks ↗</a>'],
  ['Sincronização','303','What is test_and_set() instruction?',['Testing and configuring','Atomic instruction: reads boolean and sets to true; returns old value','Setting a test','Testing memory'],1,'The correct answer is \'Atomic instruction: reads boolean and sets to true; returns old value\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#10-estruturas-struct-e-typedefs" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §10 Estruturas (struct) e Typedefs ↗</a>'],
  ['Sincronização','304','How can test_and_set() be used for locking?',['Directly storing value','Spin loop using test_and_set() until it returns false (lock acquired)','Testing only','Setting flags'],1,'The correct answer is \'Spin loop using test_and_set() until it returns false (lock acquired)\' because it accurately describes the concept.','Master concepts: Critical section, mutex, semaphore, deadlock conditions, classic problems.<br><a href="sistemas_operacoes_estudo__2_.html#66-instruções-atómicas--test_and_set-e-compare_and_swap" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §66 Instruções Atómicas — test_and_set e compare_and_swap ↗</a>'],
  ['Sincronização','305','What is a semaphore?',['A signal device','Integer synchronization primitive with wait() and signal() operations','A flag','A counter only'],1,'Semaphore = integer counter for synchronization. wait() decrements, blocks when 0. signal() increments, wakes waiter. Used for resource counting and signaling.','Remember: wait() = P() = down(). signal() = V() = up(). P and V from Dutch.<br><a href="sistemas_operacoes_estudo__2_.html#74-semáforos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §74 Semáforos ↗</a>'],
  ['Sincronização','306','What is the range of a binary semaphore?',['0 to any positive number','0 or 1 only','Negative to positive','1 to infinity'],1,'Binary semaphore has value 0 or 1, similar to mutex. Counting semaphore can have value > 1 for resource counting (e.g., buffer slots).','Remember: wait() = P() = down(). signal() = V() = up(). P and V from Dutch.<br><a href="sistemas_operacoes_estudo__2_.html#74-semáforos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §74 Semáforos ↗</a>'],
  ['Sincronização','307','What is the range of a counting semaphore?',['0 or 1 only','0 to N (number of identical resources)','Any number','Negative numbers'],1,'Semaphore = integer counter for synchronization. wait() decrements, blocks when 0. signal() increments, wakes waiter. Used for resource counting and signaling.','Remember: wait() = P() = down(). signal() = V() = up(). P and V from Dutch.<br><a href="sistemas_operacoes_estudo__2_.html#74-semáforos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §74 Semáforos ↗</a>'],
  ['Sincronização','308','What does signal() on a semaphore do?',['Sends a signal','If queue non-empty, wakes one waiter; else increments semaphore','Always increments','Blocks the process'],1,'Semaphore operations: wait(S) / P(S) decrements S, blocks if S ≤ 0. signal(S) / V(S) increments S, wakes waiting process. Atomic operations.','Remember: wait() = P() = down(). signal() = V() = up(). P and V from Dutch.<br><a href="sistemas_operacoes_estudo__2_.html#74-semáforos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §74 Semáforos ↗</a>'],
  ['Sincronização','309','What is the initial value of a binary semaphore for mutual exclusion?',['0','1 (initially unlocked)','2','Undefined'],1,'Binary semaphore has value 0 or 1, similar to mutex. Counting semaphore can have value > 1 for resource counting (e.g., buffer slots).','Remember: wait() = P() = down(). signal() = V() = up(). P and V from Dutch.<br><a href="sistemas_operacoes_estudo__2_.html#62-os-3-requisitos-de-uma-solução" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §62 Os 3 Requisitos de uma Solução ↗</a>'],
  ['Sincronização','310','What is the initial value of a counting semaphore?',['0','N (number of available resources)','1','Infinity'],1,'Semaphore = integer counter for synchronization. wait() decrements, blocks when 0. signal() increments, wakes waiter. Used for resource counting and signaling.','Remember: wait() = P() = down(). signal() = V() = up(). P and V from Dutch.<br><a href="sistemas_operacoes_estudo__2_.html#74-semáforos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §74 Semáforos ↗</a>'],
  ['Sincronização','311','How many semaphores are needed for bounded buffer?',['One','Three: mutex for exclusion, empty for empty slots, full for filled slots','Two','Infinite'],1,'Semaphore = integer counter for synchronization. wait() decrements, blocks when 0. signal() increments, wakes waiter. Used for resource counting and signaling.','Remember: wait() = P() = down(). signal() = V() = up(). P and V from Dutch.<br><a href="sistemas_operacoes_estudo__2_.html#74-semáforos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §74 Semáforos ↗</a>'],
  ['Sincronização','312','What happens if producer tries to insert into full buffer?',['Data is lost','Producer blocks on "empty" semaphore until space available','Error is generated','Buffer expands'],1,'The correct answer is \'Producer blocks on "empty" semaphore until space available\' because it accurately describes the concept.','Classic problem: Need 3 semaphores - mutex (access), empty (slots), full (items).<br><a href="sistemas_operacoes_estudo__2_.html#69-mutex-locks" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §69 Mutex Locks ↗</a>'],
  ['Sincronização','313','What happens if consumer tries to remove from empty buffer?',['Returns empty data','Consumer blocks on "full" semaphore until data available','Error is generated','Process terminates'],1,'The correct answer is \'Consumer blocks on "full" semaphore until data available\' because it accurately describes the concept.','Classic problem: Need 3 semaphores - mutex (access), empty (slots), full (items).<br><a href="sistemas_operacoes_estudo__2_.html#69-mutex-locks" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §69 Mutex Locks ↗</a>'],
  ['Sincronização','314','What is the readers-writers problem?',['Problems with reading and writing','Multiple readers concurrent allowed; writers need exclusive access','Readers and writers conflict always','Only one reader allowed'],1,'Readers-Writers: multiple readers OR one writer can access data. Challenge: balance fairness - prevent writer starvation vs reader starvation.','Tradeoff: Favor readers → writer starvation. Favor writers → reader starvation. Need balance.<br><a href="sistemas_operacoes_estudo__2_.html#79-problemas-clássicos--readers-and-writers" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §79 Problemas Clássicos — Readers and Writers ↗</a>'],
  ['Sincronização','315','What is Reader-Writer Lock (RWLock)?',['Lock for readers only','Synchronization primitive allowing concurrent readers but exclusive writers','Lock that alternates readers/writers','Two separate locks'],1,'The correct answer is \'Synchronization primitive allowing concurrent readers but exclusive writers\' because it accurately describes the concept.','Master concepts: Critical section, mutex, semaphore, deadlock conditions, classic problems.<br><a href="sistemas_operacoes_estudo__2_.html#79-problemas-clássicos--readers-and-writers" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §79 Problemas Clássicos — Readers and Writers ↗</a>'],
  ['Sincronização','316','What is the Dining Philosophers problem?',['Philosophers eating dinner','Synchronization problem: 5 philosophers, 5 chopsticks, deadlock risk if not careful','A cooking recipe','Resource allocation'],1,'Dining Philosophers illustrates deadlock/starvation. 5 philosophers, 5 forks, need 2 forks to eat. Solutions: asymmetry, resource ordering, or limit diners.','Solutions: (1) Asymmetry, (2) Resource ordering, (3) Limit to N-1 diners. Illustrates deadlock.<br><a href="sistemas_operacoes_estudo__2_.html#80-problemas-clássicos--dining-philosophers" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §80 Problemas Clássicos — Dining Philosophers ↗</a>'],
  ['Sincronização','317','How to prevent mutual exclusion?',['Force all sharing','Make resources sharable (often not feasible for printers, locks)','Prevent resource access','Cannot prevent'],1,'The correct answer is \'Make resources sharable (often not feasible for printers, locks)\' because it accurately describes the concept.','Master concepts: Critical section, mutex, semaphore, deadlock conditions, classic problems.<br><a href="sistemas_operacoes_estudo__2_.html#62-os-3-requisitos-de-uma-solução" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §62 Os 3 Requisitos de uma Solução ↗</a>'],
  ['Sincronização','318','What is process synchronization?',['Synchronizing process creation','Coordinating concurrent processes to ensure correct behavior','Timing processes','Process scheduling'],1,'The correct answer is \'Coordinating concurrent processes to ensure correct behavior\' because it accurately describes the concept.','Master concepts: Critical section, mutex, semaphore, deadlock conditions, classic problems.<br><a href="sistemas_operacoes_estudo__2_.html#54-background--porque-é-que-precisamos-de-sincronização" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §54 Background — Porque é que precisamos de sincronização? ↗</a>'],
  ['Sincronização','319','What is atomicity in synchronization?',['Small size','Operation is indivisible; cannot be interrupted or seen partially','Physics concept','Memory property'],1,'The correct answer is \'Operation is indivisible; cannot be interrupted or seen partially\' because it accurately describes the concept.','Master concepts: Critical section, mutex, semaphore, deadlock conditions, classic problems.<br><a href="sistemas_operacoes_estudo__2_.html#56-operações-atómicas" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §56 Operações Atómicas ↗</a>'],
  ['Sincronização','320','What is a race condition\'s relation to atomicity?',['No relation','Non-atomic operations can have race conditions if concurrent access','All races are atomic','Atomicity causes races'],1,'Race condition occurs when multiple processes access shared data concurrently and result depends on execution order. Leads to inconsistent state. Solution: mutual exclusion.','Remember: Race = outcome depends on execution order. Fix with synchronization (locks, semaphores).<br><a href="sistemas_operacoes_estudo__2_.html#55-critical-sections-e-race-conditions" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §55 Critical Sections e Race Conditions ↗</a>'],
  ['Sincronização','321','What is the role of a lock in synchronization?',['Preventing all access','Ensuring mutual exclusion for critical sections','Securing the computer','Protecting files'],1,'The correct answer is \'Ensuring mutual exclusion for critical sections\' because it accurately describes the concept.','Master concepts: Critical section, mutex, semaphore, deadlock conditions, classic problems.<br><a href="sistemas_operacoes_estudo__2_.html#69-mutex-locks" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §69 Mutex Locks ↗</a>'],
  ['Sincronização','322','What is a read-write lock?',['Lock for reading or writing','Multiple readers concurrent; exclusive writer access','Alternating read/write','Sequential access'],1,'The correct answer is \'Multiple readers concurrent; exclusive writer access\' because it accurately describes the concept.','Master concepts: Critical section, mutex, semaphore, deadlock conditions, classic problems.<br><a href="sistemas_operacoes_estudo__2_.html#69-mutex-locks" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §69 Mutex Locks ↗</a>'],
  ['Sincronização','323','What is lock contention?',['Argument about locks','Multiple processes competing for same lock; causes performance degradation','Lock conflict resolution','Lock initialization'],1,'The correct answer is \'Multiple processes competing for same lock; causes performance degradation\' because it accurately describes the concept.','Master concepts: Critical section, mutex, semaphore, deadlock conditions, classic problems.<br><a href="sistemas_operacoes_estudo__2_.html#69-mutex-locks" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §69 Mutex Locks ↗</a>'],
  ['Sincronização','324','How does high lock contention affect performance?',['No effect','Increases waiting time and context switches; reduces CPU efficiency','Improves performance','Has unpredictable effects'],1,'The correct answer is \'Increases waiting time and context switches; reduces CPU efficiency\' because it accurately describes the concept.','Master concepts: Critical section, mutex, semaphore, deadlock conditions, classic problems.<br><a href="sistemas_operacoes_estudo__2_.html#69-mutex-locks" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §69 Mutex Locks ↗</a>'],
  ['Sincronização','325','What is a semaphore counting rule?',['No rule','Semaphore tracks number of available instances of resource','Semaphore counts processes','Arbitrary counting'],1,'Semaphore = integer counter for synchronization. wait() decrements, blocks when 0. signal() increments, wakes waiter. Used for resource counting and signaling.','Remember: wait() = P() = down(). signal() = V() = up(). P and V from Dutch.<br><a href="sistemas_operacoes_estudo__2_.html#74-semáforos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §74 Semáforos ↗</a>'],
  ['Sincronização','326','How many times can signal() be called?',['Only once','Multiple times; each wakes one waiter or increments','Never after wait()','Exactly once per wait()'],1,'The correct answer is \'Multiple times; each wakes one waiter or increments\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#75-operações-wait-e-signal" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §75 Operações wait() e signal() ↗</a>'],
  ['Sincronização','327','What is the order of process wake-up from semaphore?',['Random','FIFO: first waiter woken first','LIFO: last waiter first','Priority-based'],1,'Semaphore = integer counter for synchronization. wait() decrements, blocks when 0. signal() increments, wakes waiter. Used for resource counting and signaling.','Remember: wait() = P() = down(). signal() = V() = up(). P and V from Dutch.<br><a href="sistemas_operacoes_estudo__2_.html#74-semáforos" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §74 Semáforos ↗</a>'],
  ['Sincronização','328','What is reader lock?',['Lock for readers','Type of read-write lock allowing concurrent readers','Lock preventing reads','Exclusive lock'],1,'The correct answer is \'Type of read-write lock allowing concurrent readers\' because it accurately describes the concept.','Master concepts: Critical section, mutex, semaphore, deadlock conditions, classic problems.<br><a href="sistemas_operacoes_estudo__2_.html#79-problemas-clássicos--readers-and-writers" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §79 Problemas Clássicos — Readers and Writers ↗</a>'],
  ['Sincronização','329','What is writer lock?',['Lock for writers','Type of read-write lock allowing exclusive writer','Lock preventing writes','Shared lock'],1,'The correct answer is \'Type of read-write lock allowing exclusive writer\' because it accurately describes the concept.','Master concepts: Critical section, mutex, semaphore, deadlock conditions, classic problems.<br><a href="sistemas_operacoes_estudo__2_.html#79-problemas-clássicos--readers-and-writers" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §79 Problemas Clássicos — Readers and Writers ↗</a>'],
  ['Sincronização','330','Can reader lock be granted while writer waiting?',['Always','Depends on implementation; some wait; some grant new readers','Never','Only on multiprocessor'],1,'The correct answer is \'Depends on implementation; some wait; some grant new readers\' because it accurately describes the concept.','Master concepts: Critical section, mutex, semaphore, deadlock conditions, classic problems.<br><a href="sistemas_operacoes_estudo__2_.html#79-problemas-clássicos--readers-and-writers" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §79 Problemas Clássicos — Readers and Writers ↗</a>'],
  ['Deadlocks','331','Which is NOT a main OS component?',['Process management','Memory management','Storage management','Furniture design'],3,'The correct answer is \'Furniture design\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#17-o-que-é-um-sistema-operativo" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §17 O que é um Sistema Operativo? ↗</a>'],
  ['Deadlocks','332','Why is direct user-mode access to hardware dangerous?',['Hardware is fragile','One program could interfere with others, crash the system, or access protected data','It would speed up the system too much','No danger exists'],1,'The correct answer is \'One program could interfere with others, crash the system, or access protected data\' because it accurately describes the concept.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#81-caracterização-de-deadlock--4-condições-necessárias" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §81 Caracterização de Deadlock — 4 Condições Necessárias ↗</a>'],
  ['Deadlocks','333','What is livelock?',['A process stuck in a loop','Processes continuously change state but make no progress','Processes completely blocked','Process priority inversion'],1,'The correct answer is \'Processes continuously change state but make no progress\' because it accurately describes the concept.','Master concepts: Critical section, mutex, semaphore, deadlock conditions, classic problems.<br><a href="sistemas_operacoes_estudo__2_.html#81-caracterização-de-deadlock--4-condições-necessárias" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §81 Caracterização de Deadlock — 4 Condições Necessárias ↗</a>'],
  ['Deadlocks','334','What causes deadlock in dining philosophers?',['Hunger','Each takes left chopstick; all wait for right; circular wait','Philosophers being slow','Only one solution exists'],1,'Dining Philosophers illustrates deadlock/starvation. 5 philosophers, 5 forks, need 2 forks to eat. Solutions: asymmetry, resource ordering, or limit diners.','Solutions: (1) Asymmetry, (2) Resource ordering, (3) Limit to N-1 diners. Illustrates deadlock.<br><a href="sistemas_operacoes_estudo__2_.html#80-problemas-clássicos--dining-philosophers" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §80 Problemas Clássicos — Dining Philosophers ↗</a>'],
  ['Deadlocks','335','How can dining philosophers deadlock be prevented?',['By not eating','Allow only N-1 at table, asymmetric pickup order, or atomic acquisition','Force eating order','Deadlock cannot be prevented'],1,'Dining Philosophers illustrates deadlock/starvation. 5 philosophers, 5 forks, need 2 forks to eat. Solutions: asymmetry, resource ordering, or limit diners.','Solutions: (1) Asymmetry, (2) Resource ordering, (3) Limit to N-1 diners. Illustrates deadlock.<br><a href="sistemas_operacoes_estudo__2_.html#80-problemas-clássicos--dining-philosophers" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §80 Problemas Clássicos — Dining Philosophers ↗</a>'],
  ['Deadlocks','336','What is deadlock?',['A lock that is dead','Set of processes permanently blocked waiting for resources held by each other','A process not responding','A failure'],1,'The correct answer is \'Set of processes permanently blocked waiting for resources held by each other\' because it accurately describes the concept.','Master concepts: Critical section, mutex, semaphore, deadlock conditions, classic problems.<br><a href="sistemas_operacoes_estudo__2_.html#81-caracterização-de-deadlock--4-condições-necessárias" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §81 Caracterização de Deadlock — 4 Condições Necessárias ↗</a>'],
  ['Deadlocks','337','What are the four Coffman conditions for deadlock?',['Concurrency, competition, coverage, control','Mutual exclusion, hold-and-wait, no preemption, circular wait','Blocking, waiting, running, ready','Process, processor, program, priority'],1,'4 necessary conditions for deadlock (all must hold): (1) Mutual Exclusion, (2) Hold and Wait, (3) No Preemption, (4) Circular Wait. Break ANY one to prevent.','CRITICAL: 4 conditions - Mutual exclusion, Hold-wait, No-preemption, Circular-wait. Break ONE to prevent.<br><a href="sistemas_operacoes_estudo__2_.html#81-caracterização-de-deadlock--4-condições-necessárias" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §81 Caracterização de Deadlock — 4 Condições Necessárias ↗</a>'],
  ['Deadlocks','338','What do edges represent in RAG?',['Communication','Request edges: process → resource (wants); Assignment edges: resource → process (held)','Dependencies only','Scheduling'],1,'RAG: processes (circles), resources (squares). Request edge (P→R), Assignment edge (R→P). Cycle with single instance per type = deadlock. Otherwise, possible deadlock.','Study the underlying concepts and practice with examples.<br><a href="sistemas_operacoes_estudo__2_.html#82-resource-allocation-graph" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §82 Resource Allocation Graph ↗</a>'],
  ['Deadlocks','339','What is Banker\'s Algorithm?',['An algorithm for banking operations','Deadlock avoidance: grant request only if system remains safe','Process scheduling','Memory allocation'],1,'Banker\'s Algorithm checks if granting resource request leaves system in safe state. Safe = exists sequence where all processes can finish. If safe, grant; else deny/wait.','Remember: Banker checks BEFORE granting. Safe state = can finish all. Unsafe ≠ deadlock but risky.<br><a href="sistemas_operacoes_estudo__2_.html#86-deadlock-avoidance-e-safe-state" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §86 Deadlock Avoidance e Safe State ↗</a>'],
  ['Deadlocks','340','How does Banker\'s Algorithm work?',['Randomly','Before granting resource, simulates granting and checks if resulting state safe','Always grants','Never grants'],1,'Banker\'s Algorithm checks if granting resource request leaves system in safe state. Safe = exists sequence where all processes can finish. If safe, grant; else deny/wait.','Remember: Banker checks BEFORE granting. Safe state = can finish all. Unsafe ≠ deadlock but risky.<br><a href="sistemas_operacoes_estudo__2_.html#86-deadlock-avoidance-e-safe-state" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §86 Deadlock Avoidance e Safe State ↗</a>'],
  ['Deadlocks','341','Can deadlock resolve itself?',['Yes; always','No; requires external intervention','Sometimes depends on processes','Yes, if processes exit'],1,'The correct answer is \'No; requires external intervention\' because it accurately describes the concept.','Master concepts: Critical section, mutex, semaphore, deadlock conditions, classic problems.<br><a href="sistemas_operacoes_estudo__2_.html#81-caracterização-de-deadlock--4-condições-necessárias" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §81 Caracterização de Deadlock — 4 Condições Necessárias ↗</a>'],
  ['Deadlocks','342','For processes P1(burst=24), P2(burst=3), P3(burst=3) arriving together, average waiting time under FCFS is:',['0ms','17ms','10ms','27ms'],1,'P1 waits 0, P2 waits 24, P3 waits 27. Average = (0+24+27)/3 = 17ms. SJF order P2,P3,P1: (0+3+6)/3=3ms — much better.','This classic example illustrates why SJF outperforms FCFS on average waiting time.<br><a href="sistemas_operacoes_estudo__2_.html#45-critérios-de-escalonamento" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §45 Critérios de Escalonamento ↗</a>'],
  ['Deadlocks','343','Exponential averaging for burst prediction computes the next estimate as:',['Only the most recent burst time','Only the very first burst ever observed','A weighted combination: α × recent_burst + (1−α) × previous_estimate','The maximum observed burst time'],2,'τ_{n+1} = α·t_n + (1−α)·τ_n. With α=0.5, recent and historical bursts are equally weighted. Recent bursts influence more with higher α.','Exponential averaging is the standard technique for next-burst prediction in SJF implementation.<br><a href="sistemas_operacoes_estudo__2_.html#48-shortest-job-first-sjf-e-previsão-do-próximo-burst" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §48 Shortest-Job-First (SJF) e Previsão do Próximo Burst ↗</a>'],
  ['Deadlocks','344','A deadlock is defined as:',['A process consuming 100% CPU','A set of processes permanently blocked — each waiting for a resource held by another in the set','A process with too many open files','The CPU being idle while processes are in the ready queue'],1,'Deadlock: circular wait where each process holds a resource and waits for one held by another. No process can proceed without external intervention.','The 4 Coffman necessary conditions: mutual exclusion, hold and wait, no preemption, circular wait.<br><a href="sistemas_operacoes_estudo__2_.html#81-caracterização-de-deadlock--4-condições-necessárias" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §81 Caracterização de Deadlock — 4 Condições Necessárias ↗</a>'],
  ['Deadlocks','345','The four necessary conditions for deadlock (Coffman conditions) are:',['Starvation, aging, preemption, circular wait','Mutual exclusion, hold and wait, no preemption, circular wait','Mutual exclusion, preemption, priority inversion, livelock','Starvation, mutual exclusion, aging, no preemption'],1,'ALL four must hold simultaneously for deadlock. Preventing any single one prevents deadlock. Coffman (1971) identified these as: mutual exclusion, hold-and-wait, no preemption, circular wait.','Each condition is necessary; together they are sufficient for deadlock potential.<br><a href="sistemas_operacoes_estudo__2_.html#81-caracterização-de-deadlock--4-condições-necessárias" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §81 Caracterização de Deadlock — 4 Condições Necessárias ↗</a>'],
  ['Deadlocks','346','The "no preemption" condition for deadlock means:',['The OS cannot schedule processes','A resource held by a process cannot be forcibly taken — only voluntarily released','No timer interrupts exist','Processes cannot be terminated'],1,'No preemption: once a process holds a resource, the OS cannot forcibly take it back — the process must release it voluntarily. Breaking this (allowing preemption) can prevent deadlock.','CPU is preemptible (timer interrupt). Printer, file lock — not easily preemptible.<br><a href="sistemas_operacoes_estudo__2_.html#81-caracterização-de-deadlock--4-condições-necessárias" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §81 Caracterização de Deadlock — 4 Condições Necessárias ↗</a>'],
  ['Deadlocks','347','A Resource Allocation Graph (RAG) with no cycles:',['Always has a deadlock','Never has a deadlock','May or may not have deadlock','Always has starvation'],1,'No cycle in RAG = no deadlock, guaranteed. A cycle is a necessary condition for deadlock.','For single-instance resources: cycle ↔ deadlock. For multi-instance: cycle = possible deadlock.<br><a href="sistemas_operacoes_estudo__2_.html#20-princípios-de-um-so" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §20 Princípios de um SO ↗</a>'],
  ['Deadlocks','348','In a RAG with multi-instance resources, a cycle means:',['Definite deadlock','Possible deadlock — requires further analysis','Definite no deadlock','The system needs more resources immediately'],1,'With multiple resource instances, a cycle is necessary but not sufficient for deadlock. The Banker\'s Algorithm can determine if actual deadlock exists.','Single-instance: cycle = deadlock. Multi-instance: cycle = maybe deadlock — must check further.<br><a href="sistemas_operacoes_estudo__2_.html#82-resource-allocation-graph" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §82 Resource Allocation Graph ↗</a>'],
  ['Deadlocks','349','The Banker\'s Algorithm is a technique for:',['Deadlock detection after it occurs','Deadlock avoidance — checking if granting a request keeps the system in a safe state','Deadlock recovery by killing processes','Deadlock prevention by resource ordering'],1,'Banker\'s Algorithm (Dijkstra): before granting a request, simulate the allocation and run a safety check. If the resulting state is safe, grant; otherwise make the process wait.','Named after a bank that only loans money if it can still honor all possible client withdrawals.<br><a href="sistemas_operacoes_estudo__2_.html#86-deadlock-avoidance-e-safe-state" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §86 Deadlock Avoidance e Safe State ↗</a>'],
  ['Deadlocks','350','A "safe state" in the context of deadlock avoidance means:',['No process is currently waiting for resources','A safe sequence exists: all processes can eventually complete without deadlock','All resources are fully allocated','No circular wait currently exists'],1,'Safe state: there exists at least one sequence in which every process can acquire its maximum resources, execute to completion, and release — without deadlock occurring.','OS maintains safe state by only granting requests that keep the system in a safe state.<br><a href="sistemas_operacoes_estudo__2_.html#86-deadlock-avoidance-e-safe-state" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §86 Deadlock Avoidance e Safe State ↗</a>'],
  ['Deadlocks','351','The "Need" matrix in Banker\'s Algorithm is computed as:',['Max − Allocation','Allocation − Max','Available − Max','Allocation + Available'],0,'Need[i][j] = Max[i][j] − Allocation[i][j]. Represents how many more resources of each type process i may still request before completing.','Banker\'s data structures: Available vector, Max matrix, Allocation matrix, Need matrix.<br><a href="sistemas_operacoes_estudo__2_.html#86-deadlock-avoidance-e-safe-state" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §86 Deadlock Avoidance e Safe State ↗</a>'],
  ['Deadlocks','352','An unsafe state in Banker\'s Algorithm means:',['Deadlock has definitely occurred','No safe sequence exists — the OS cannot guarantee all processes will complete','No process is currently running','Some resources are unallocated'],1,'Unsafe state: no safe sequence exists. Deadlock is not guaranteed (processes may not request maximum), but OS cannot ensure it will be avoided. Banker\'s prevents entering unsafe states.','Unsafe ≠ deadlocked. It means OS cannot guarantee no deadlock will occur.<br><a href="sistemas_operacoes_estudo__2_.html#86-deadlock-avoidance-e-safe-state" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §86 Deadlock Avoidance e Safe State ↗</a>'],
  ['Deadlocks','353','Deadlock prevention works by:',['Detecting deadlocks after they occur and recovering','Structurally ensuring at least one of the four necessary conditions can never hold','Using Banker\'s Algorithm on every request','Terminating random processes periodically'],1,'Prevention: eliminate one Coffman condition by design. E.g., require all-resources-at-once (eliminates hold-and-wait), or impose resource ordering (eliminates circular wait).','Prevention is conservative — may significantly reduce resource utilization or system flexibility.<br><a href="sistemas_operacoes_estudo__2_.html#85-deadlock-prevention" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §85 Deadlock Prevention ↗</a>'],
  ['Deadlocks','354','Imposing a global ordering on resource types prevents deadlock by eliminating:',['Mutual exclusion','Hold and wait','No preemption','Circular wait'],3,'Total ordering: all processes must request resources in the same fixed order (e.g., R1 before R2 before R3). This makes circular wait structurally impossible.','If all processes acquire locks in the same order, no circular dependency can form.<br><a href="sistemas_operacoes_estudo__2_.html#85-deadlock-prevention" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §85 Deadlock Prevention ↗</a>'],
  ['Deadlocks','355','Deadlock recovery can be accomplished by:',['Only rebooting the entire system','Process termination or resource preemption from selected processes','Increasing available memory','Reducing CPU clock speed'],1,'Two recovery approaches: (1) Terminate deadlocked processes (all at once, or one at a time). (2) Preempt resources — take from some processes and give to others, rolling back victims to a safe state.','Minimize recovery cost: consider priority, how long running, resources held, resources needed by others.<br><a href="sistemas_operacoes_estudo__2_.html#88-recovery-from-deadlock" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §88 Recovery from Deadlock ↗</a>'],
  ['Deadlocks','356','When selecting which process to terminate for deadlock recovery, the OS should:',['Always terminate all deadlocked processes at once','Minimize cost — consider priority, progress made, resources held, and how many processes must be stopped','Terminate the process using the most CPU','Terminate processes in FCFS arrival order'],1,'Cost-minimizing victim selection: terminate process that causes least disruption — low priority, least computation done, holds resources others need most, fewest other processes must be terminated.','Partial termination (one at a time with re-checks) wastes more CPU but minimizes unnecessary kills.<br><a href="sistemas_operacoes_estudo__2_.html#88-recovery-from-deadlock" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §88 Recovery from Deadlock ↗</a>'],
  ['Deadlocks','357','Livelock differs from deadlock in that:',['Livelock processes are permanently blocked','Livelock processes keep actively changing state in response to each other but make no progress','Livelock has no circular dependency','Livelock only occurs with a single process'],1,'Livelock: processes are not blocked but continuously react to each other without making progress (like two people repeatedly stepping the same direction in a corridor). No forward progress — similar outcome to deadlock.','Classic: two processes each repeatedly release and re-request the same conflicting resources.<br><a href="sistemas_operacoes_estudo__2_.html#81-caracterização-de-deadlock--4-condições-necessárias" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §81 Caracterização de Deadlock — 4 Condições Necessárias ↗</a>'],
  ['Deadlocks','358','The "ostrich algorithm" for deadlock is:',['Always prevent deadlocks proactively','Pretend deadlocks cannot happen — ignore the problem','Detect and immediately kill all processes','Always run the Banker\'s Algorithm'],1,'Ostrich algorithm: ignore deadlock. Justified when deadlocks are extremely rare and the cost of prevention/detection overhead exceeds the cost of occasional system reboots. Used by Unix/Windows for some resource types.','Named after the myth of ostriches burying their heads. Pragmatic approach for low-deadlock-risk systems.<br><a href="sistemas_operacoes_estudo__2_.html#84-métodos-para-lidar-com-deadlocks" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §84 Métodos para lidar com Deadlocks ↗</a>'],
  ['Deadlocks','359','In the Banker\'s Algorithm, if Available = [3,3,2] and a request is [2,1,1], Available after tentative grant is:',['[3,3,2] — no change','[1,2,1]','[5,4,3]','[2,2,1]'],1,'Available − request = [3−2, 3−1, 2−1] = [1,2,1]. This is the first step in Banker\'s safety check: tentatively update Available and Allocation, then run safety algorithm.','Banker\'s: tentatively allocate → run safety check → if safe, grant; if unsafe, make process wait.<br><a href="sistemas_operacoes_estudo__2_.html#86-deadlock-avoidance-e-safe-state" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §86 Deadlock Avoidance e Safe State ↗</a>'],
  ['Deadlocks','360','What is the primary limitation of the Banker\'s Algorithm in practice?',['It cannot detect cycles in the RAG','Processes must declare maximum resource needs in advance, which is often impossible to know','It only works for single-instance resources','It requires terminating processes on every request'],1,'Banker\'s requires knowing each process\'s maximum resource claim upfront. In practice this is often unknown. Also assumes a fixed number of processes and resource types — unrealistic for dynamic systems.','Practical systems often prefer prevention (lock ordering) or detection+recovery over Banker\'s.<br><a href="sistemas_operacoes_estudo__2_.html#86-deadlock-avoidance-e-safe-state" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §86 Deadlock Avoidance e Safe State ↗</a>'],
  ['Deadlocks','361','Starvation can result from deadlock recovery when:',['Recovery terminates all processes simultaneously','The same process is repeatedly chosen as victim (preempted or terminated) to resolve deadlocks','Recovery always terminates only one process ever','Deadlock cannot be detected accurately'],1,'If the victim selection algorithm always picks the same low-cost process, that process is perpetually rolled back and never completes. Must include starvation prevention: limit how many times a process can be victimized.','Add "number of times previously preempted" as a cost factor in victim selection.<br><a href="sistemas_operacoes_estudo__2_.html#88-recovery-from-deadlock" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §88 Recovery from Deadlock ↗</a>'],
  ['Deadlocks','362','What does it mean for a state to have a safe sequence P2, P1, P3?',['P2 must always run before P1 in scheduling','P2 can finish with current resources; after releasing, P1 can finish; after P1 releases, P3 can finish','P3 has the highest scheduling priority','These processes will deadlock in this order'],1,'Safe sequence: P2\'s remaining needs ≤ available → P2 runs and releases → now P1\'s needs met → P1 runs and releases → P3\'s needs met → P3 completes. All finish — safe state confirmed.','If even one safe sequence exists, the state is safe (deadlock avoidable with proper scheduling).<br><a href="sistemas_operacoes_estudo__2_.html#86-deadlock-avoidance-e-safe-state" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §86 Deadlock Avoidance e Safe State ↗</a>'],
  ['Deadlocks','363','Deadlock vs. starvation: the key difference is:',['They are exactly the same phenomenon','Deadlock: processes block each other permanently. Starvation: a process is perpetually skipped by the scheduler but resources are theoretically reachable','Starvation always involves circular wait','Deadlock can only occur with exactly one process'],1,'Deadlock: no process in the set can ever proceed — resources are circularly held. Starvation: resources exist and could be granted, but the scheduler never picks the starving process.','Starvation can end (if scheduling policy changes or aging is applied). Deadlock requires intervention.<br><a href="sistemas_operacoes_estudo__2_.html#81-caracterização-de-deadlock--4-condições-necessárias" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §81 Caracterização de Deadlock — 4 Condições Necessárias ↗</a>'],
  ['Deadlocks','364','Resource preemption for deadlock recovery requires:',['Immediately terminating the victim process','Selecting a victim, preempting its resources, rolling it back to a safe checkpoint, and restarting from there','Never rolling back any process','Only preempting CPU time, never memory or devices'],1,'Preemption recovery steps: (1) select victim (minimum cost). (2) Roll back victim to a safe state where it held fewer resources. (3) Restart from that checkpoint. Must prevent the same process being victimized repeatedly.','Rollback requires checkpointing — saving process state at regular intervals.<br><a href="sistemas_operacoes_estudo__2_.html#88-recovery-from-deadlock" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §88 Recovery from Deadlock ↗</a>'],
  ['Deadlocks','365','In a system with only single-instance resources, which is the most efficient deadlock detection method?',['Banker\'s Algorithm','Cycle detection in the wait-for graph','Randomly terminating processes','Checking Available vector periodically'],1,'For single-instance resources, maintain a wait-for graph and periodically check for cycles. Cycle detection runs in O(V+E). Much simpler and cheaper than Banker\'s for single-instance case.','Wait-for graph cycle detection: O(n²) worst case for n processes.<br><a href="sistemas_operacoes_estudo__2_.html#87-deadlock-detection" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §87 Deadlock Detection ↗</a>'],
  ['Deadlocks','366','For which scenario is the deadlock detection + recovery approach most appropriate?',['Safety-critical real-time systems','Systems where deadlocks are rare and avoidance/prevention overhead is too costly','Systems where deadlocks occur every second','Embedded systems with no OS'],1,'Detection+recovery makes sense when: deadlocks are infrequent, the overhead of Banker\'s Algorithm or structural prevention is too high, and recovery cost (aborting a process) is acceptable.','Many general-purpose OSes use ostrich or detection+recovery for most resource types.<br><a href="sistemas_operacoes_estudo__2_.html#87-deadlock-detection" target="_blank" style="color:#5b8af0;text-decoration:none;border:1px solid rgba(91,138,240,.35);padding:2px 8px;border-radius:6px;display:inline-block;margin-top:6px;font-size:.78rem;">📖 §87 Deadlock Detection ↗</a>']
];
